INSERT INTO public.profile VALUES (89, 'Hello! In the past I was volunteering in a cafe where we were taking care of refugee kids while their parents were attending a german course. Something like this or something like doing arts or crafts / leisure time activities with the kids, would be awesome. I habe basic skills in arabic. And I would like to volunteer approx 2h a week. Kind regards, Jenny', NULL);
INSERT INTO public.profile VALUES (90, 'Ich habe leider noch nicht meinen Stundenplan für die Uni bekommen deswegen kann es gut sein, dass die Zeiten an welchen ich Zeit habe sich nochmal verändern. Und ich kann erst ab dem 6.10 wieder weil ich dann erst zurück nach Berlin komme', NULL);
INSERT INTO public.profile VALUES (91, 'I am very flexible, I can volunteer when most convenient for you!', NULL);
