INSERT INTO public.profile VALUES (335, 'hi, zu den Zeiten: ich habe eine Auswahl angegeben, die für mich grundsätzlich regelmäßig möglich sind. Insgesamt kann ich mir so 4-8h pro Woche vorstellen. Machmal muss ich wegen des Studiums ist Arbeit über mehrere Tage wegfahren. Ich habe eine Schauspielausbildung und kann gerne, was mit Sprechen und Vorlesen machen. Außerdem Interesse an schulischer Mathematik. Gruppen geleitet habe ich noch nicht und ist mir möglicherweise zu schwierig. Ich habe ein Führungszeugnis von 2021/2022, ist das aktuell genug? Freue mich über ein Kennenlernen.', NULL);
