INSERT INTO public.field_translation VALUES (69, 'title', 1833, 'category', 1, 'German Language Support');
INSERT INTO public.field_translation VALUES (70, 'title', 1540, 'category', 1, 'Deutsche Unterstützung');
INSERT INTO public.field_translation VALUES (71, 'description', 1833, 'category', 1, 'Fluent in German? Support refugees by teaching german at language cafes and tutoring privately or in groups.');
INSERT INTO public.field_translation VALUES (72, 'description', 1540, 'category', 1, 'Sprichst du fließend Deutsch? Unterstütze Geflüchtete, indem du in Sprachcafés unterrichtest oder Nachhilfe gibst – privat oder in Gruppen.');
INSERT INTO public.field_translation VALUES (73, 'title', 1833, 'category', 2, 'Childcare');
INSERT INTO public.field_translation VALUES (74, 'title', 1540, 'category', 2, 'Kinderbetreuung');
INSERT INTO public.field_translation VALUES (75, 'description', 1833, 'category', 2, 'We are looking for volunteers to support children in refugee accommodation centers by assisting in daycare or helping with homework. Experience with children is a plus!');
INSERT INTO public.field_translation VALUES (76, 'description', 1540, 'category', 2, 'Hilf Kindern in Unterkünften – bei der Betreuung am Tag oder den Hausaufgaben. Erfahrung mit Kindern ist ein Plus!');
INSERT INTO public.field_translation VALUES (77, 'title', 1833, 'category', 3, 'Skills Based Volunteering');
INSERT INTO public.field_translation VALUES (78, 'title', 1540, 'category', 3, 'Ehrenamt mit Fachkenntnissen');
INSERT INTO public.field_translation VALUES (79, 'description', 1833, 'category', 3, 'Some opportunities may offer a chance to use your special expertise, such as bike repair, gardening, musical skills, or organizational savvy.');
INSERT INTO public.field_translation VALUES (80, 'description', 1540, 'category', 3, 'Nutze deine Fähigkeiten – z. B. Fahrradreparatur, Gartenarbeit oder Musik.');
INSERT INTO public.field_translation VALUES (81, 'title', 1833, 'category', 4, 'Events');
INSERT INTO public.field_translation VALUES (82, 'title', 1540, 'category', 4, 'Veranstaltungen');
INSERT INTO public.field_translation VALUES (83, 'description', 1833, 'category', 4, 'Occasionally events require unique support from volunteers. These might be festivals, dinners, outings, cultural activities, a day of setting up a clothes sorting station, gardening, or a workshop.');
INSERT INTO public.field_translation VALUES (84, 'description', 1540, 'category', 4, 'Manche Events brauchen extra Hilfe – Festivals, Ausflüge, Gartenarbeit oder Kleiderkammer einrichten.');
INSERT INTO public.field_translation VALUES (85, 'title', 1833, 'category', 5, 'Sport activities');
INSERT INTO public.field_translation VALUES (86, 'title', 1540, 'category', 5, 'Sportliche Aktivitäten');
