INSERT INTO public.opportunity VALUES (1, 'Begleitung zum Termin für schulärztliche Untersuchung im Gesundheitsamt Treptow', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:17.401521', '2025-11-01 20:51:17.401521', 15, 1);
INSERT INTO public.opportunity VALUES (2, 'Hilfe beim Deutschlernen', 'volunteering', 'Das Sprachniveau ist sehr unterschiedlich – einige Bewohnerinnen sprechen schon recht gut Deutsch, andere haben geringe oder gar keine Kenntnisse. Es ist also eine gemischte Gruppe.    Grundsätzlich geht es darum, die Grundlagen der deutschen Sprache zu vermitteln und die Bewohnerinnen im Alltag sprachlich zu stärken.Besonders hilfreich wären feste Lernzeiten, Lehrmaterialien sowie Unterstützung durch Ehrenamtliche oder Lehrkräfte. 
INSERT INTO public.opportunity VALUES (3, 'Begleitung zur Radiologie', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.427389', '2025-11-01 20:51:20.427389', 521, 3);
INSERT INTO public.opportunity VALUES (4, 'Begleitung zum Arzt', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.490186', '2025-11-01 20:51:20.490186', 536, 4);
INSERT INTO public.opportunity VALUES (5, 'Begleitung zum Arzttermin', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.506318', '2025-11-01 20:51:20.506318', 541, 4);
INSERT INTO public.opportunity VALUES (6, 'Begleitung zur Urologie', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.53359', '2025-11-01 20:51:20.53359', 542, 5);
INSERT INTO public.opportunity VALUES (7, 'Begleitung zur Endokrinologie', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.549013', '2025-11-01 20:51:20.549013', 543, 5);
INSERT INTO public.opportunity VALUES (8, 'Kinderphysiotherapie - Begleitung', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.571394', '2025-11-01 20:51:20.571394', 544, 6);
INSERT INTO public.opportunity VALUES (9, 'Begleitung zum Besprechungstermin', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.593648', '2025-11-01 20:51:20.593648', 545, 7);
INSERT INTO public.opportunity VALUES (10, 'Mitarbeit beim Basteln mit unserem Ehrenamtlichen Boris. Er ist ein Bastler mit Herz & Seele. (www.projekt-bastelbogen.de)', 'volunteering', 'Boris, der Bastler, hätte gerne einen bastelbegeisterten Menschen, der mit ihm eine kleine Gruppe von Kindern, max. 2-4, betreut, selbst mit bastelt und gerne mit Kindern arbeitet. Es reicht aus, wenn diese Person Schere und Lineal mitbringt. Die Tage und Uhrzeiten sind nicht festgelegt und können mit Boris und unserem Leitungsteam abgesprochen werden. Boris'' Kontakt: b.voigt@posteo.de', 'noTranslation', '', '2025-11-01 20:51:20.624631', '2025-11-01 20:51:20.624631', 546, 8);
INSERT INTO public.opportunity VALUES (11, 'Begleitung (Übersetzung) zur Schuldnerberatung', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.652807', '2025-11-01 20:51:20.652807', 547, 9);
INSERT INTO public.opportunity VALUES (12, 'Russisch Dolmetschen beim Kardiologen', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.681772', '2025-11-01 20:51:20.681772', 548, 10);
INSERT INTO public.opportunity VALUES (13, 'Sprachmittlung und Begleitung Deutsch Russisch MRT Termin', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.702715', '2025-11-01 20:51:20.702715', 549, 11);
INSERT INTO public.opportunity VALUES (14, 'FrauenCafe', 'volunteering', 'Wir möchten in unserer Einrichtung einmal pro Woche ein Frauencafe (Sprachcafe) organisieren. Dafür suchen wir engagierte Freiwillige, die Freude am Gespräch haben und andere motivieren, mitzuerzählen. Gemeinsam wollen wir in entspannter Atmosphäre Deutsch sprechen, voneinander lernen und uns austauschen.', 'noTranslation', '', '2025-11-01 20:51:20.746089', '2025-11-01 20:51:20.746089', 550, 12);
INSERT INTO public.opportunity VALUES (15, 'Wegbegleitung', 'volunteering', '', 'englishOk', '', '2025-11-01 20:51:20.770658', '2025-11-01 20:51:20.770658', 551, 13);
INSERT INTO public.opportunity VALUES (16, 'Flinta Workshop zu Körper', 'volunteering', '2 Stunden Sprachmittlung (dt. - türk.) in einem Flinta Workshop zu Körper, Gesundheit und Zyklus', 'noTranslation', '', '2025-11-01 20:51:20.789431', '2025-11-01 20:51:20.789431', 552, 7);
INSERT INTO public.opportunity VALUES (17, 'Begleitung zur HNO', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.804724', '2025-11-01 20:51:20.804724', 553, 5);
INSERT INTO public.opportunity VALUES (18, 'Begleitung zur Gastroenterologie', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.820971', '2025-11-01 20:51:20.820971', 554, 5);
INSERT INTO public.opportunity VALUES (19, 'Russisch/Ukrainisch Dolmetscher*in im Virchow Klinikum', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.841795', '2025-11-01 20:51:20.841795', 555, 10);
INSERT INTO public.opportunity VALUES (20, 'Freiwillige Helfer*innen gesucht für Sommerfest am 29.08. in der Aufnahmeeinrichtung', 'volunteering', 'Für unser Sommerfest am 29. August in der Aufnahmeeinrichtung am Blumberger Damm suchen wir noch freiwillige Helfer*innen! 
INSERT INTO public.opportunity VALUES (21, 'Sprachmittlung Deutsch Englisch für Behörde', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.886202', '2025-11-01 20:51:20.886202', 557, 11);
INSERT INTO public.opportunity VALUES (22, 'Arzt Begleitung', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.898957', '2025-11-01 20:51:20.898957', 558, 6);
INSERT INTO public.opportunity VALUES (23, 'Sprachmittlung für Beratungstermin zum Thema Sorgerecht', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:20.925138', '2025-11-01 20:51:20.925138', 559, 14);
INSERT INTO public.opportunity VALUES (24, 'Familie bei Renovierungsarbeiten unterstützen (Streichen, spachteln etc.)', 'volunteering', 'Eine Familie unserer Unterkunft hat endlich eine Wohnung gefunden. Leider ist diese sehr renovierungsbedürftig und sie würden sich über jeden Helfenden Hand freuen.
INSERT INTO public.opportunity VALUES (25, 'Unterstütze bei der Kinderbetreuung', 'volunteering', 'Wir suchen Freiwillige, die sich um die Kinder kümmern, mit ihnen spielen und eine schöne Zeit haben.', 'noTranslation', '', '2025-11-01 20:51:20.976471', '2025-11-01 20:51:20.976471', 561, 12);
INSERT INTO public.opportunity VALUES (26, 'Unterstützung in der Kleiderkammer', 'volunteering', 'Wir suchen jemand für unsere Kleiderkammer (Spenden aussortieren und für die Bewohnenden zur Verfügung stellen). Das wäre mittwochs 11-13:00.', 'noTranslation', '', '2025-11-01 20:51:21.000424', '2025-11-01 20:51:21.000424', 562, 4);
INSERT INTO public.opportunity VALUES (27, 'Klavierunterricht für Kinder,Kinderbetreuung im Jugendraum', 'volunteering', 'Wir haben einen Jugendraum vor kurzem und würden gerne paar Ehrenamtlichen haben,die Aktivitäten für Kinder anbieten.Auch haben wir auch paar Keyboards für Klavier und würden  uns freuen auf Freiwillige freuen,die im Bereich was machen wollen..', 'noTranslation', '', '2025-11-01 20:51:21.026442', '2025-11-01 20:51:21.026442', 563, 4);
INSERT INTO public.opportunity VALUES (28, 'Organisiere Sportaktivitäten für Kinder', 'volunteering', 'Wir suchen Ehrenamtlichen für Sportaktivitäten für Kinder (Tischtennis oder Fußball).', 'noTranslation', '', '2025-11-01 20:51:21.046957', '2025-11-01 20:51:21.046957', 564, 4);
INSERT INTO public.opportunity VALUES (29, 'Nachhilfeunterricht für Schulkinder', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:21.062407', '2025-11-01 20:51:21.062407', 565, 4);
INSERT INTO public.opportunity VALUES (30, 'Unterstützung für Gartenprojekt:Hochbeet', 'volunteering', 'Wir werden mit den Bewohnenden Hochbeet pflanzen.Dafür benötigen wir Unterstützung.Idealerweise Jemand der ein bisschen Erfahrung hat oder einfach Lust hat,zu unterstützen.', 'noTranslation', '', '2025-11-01 20:51:21.087346', '2025-11-01 20:51:21.087346', 566, 4);
INSERT INTO public.opportunity VALUES (31, 'Arzt Begleitung', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:21.103178', '2025-11-01 20:51:21.103178', 567, 6);
INSERT INTO public.opportunity VALUES (32, 'Kinderschminken und weiteres beim Sommerfest in Grünau', 'volunteering', 'Wir suchen nach Freiwilligen, die uns bei Kinderschminken unterstützen können. Falls es noch weitere Freiwillige gibt, die uns an diesem Tag unterstützen könnten, wäre das ebenfalls wunderbar.', 'noTranslation', '', '2025-11-01 20:51:21.139754', '2025-11-01 20:51:21.139754', 568, 16);
INSERT INTO public.opportunity VALUES (33, 'Co-Leitung für Sprachcafe', 'volunteering', 'Es gibt schon eine erfahrene Freiwillige, die sich um die Planung des Sprachcafes kümmert. Wir suchen eine deutsche Muttersprachler:in, die Dienstag Nachmittags von 15-16:30 Zeit und Lust hat gemeinsam das Cafe zu betreuen. Keine Erfahrung im Unterrichten ist notwendig.', 'noTranslation', '', '2025-11-01 20:51:21.155921', '2025-11-01 20:51:21.155921', 569, 7);
INSERT INTO public.opportunity VALUES (34, 'Kinderaktivitäten gestalten', 'volunteering', 'Wir brauchen dringend montags von 16-18 Uhr Freiwillige, die mit den Kindern im Garten spielen oder basteln während die Frauen an Workshops teilnehmen.', 'noTranslation', '', '2025-11-01 20:51:21.178019', '2025-11-01 20:51:21.178019', 570, 7);
INSERT INTO public.opportunity VALUES (35, 'Frauencafé, Deutschkonversation', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:21.201884', '2025-11-01 20:51:21.201884', 571, 17);
INSERT INTO public.opportunity VALUES (36, 'Nachhilfe Grundschule', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:21.217134', '2025-11-01 20:51:21.217134', 572, 17);
INSERT INTO public.opportunity VALUES (37, 'Deutsch lernen und dabei Spaß haben', 'volunteering', 'Eine Gruppe von Jugendlichen möchte gerne ihr Deutsch verbessern und üben, und dabei auch Spaß haben. Gesucht wird eine Person, die mit den Jüngs und Mädels Deutsch sprechen möchte.', 'noTranslation', '', '2025-11-01 20:51:21.243942', '2025-11-01 20:51:21.243942', 573, 18);
INSERT INTO public.opportunity VALUES (38, 'Bewegungsangebote und Tanzen', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:21.261484', '2025-11-01 20:51:21.261484', 574, 17);
INSERT INTO public.opportunity VALUES (39, 'Deutschunterricht für Erwachsene', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:21.277723', '2025-11-01 20:51:21.277723', 575, 4);
INSERT INTO public.opportunity VALUES (40, 'Unterstütze Bewohner*innen beim Deutschlernen in Lichtenberg', 'volunteering', 'Die Bewohner*innen einer Unterkunft in Lichtenberg wünschen sich Unterstützung beim Deutschlernen und bei der Verbesserung ihrer Deutschkenntnisse. Sie können sich ehrenamtlich engagieren, indem Sie eine Person mit Nachhilfeunterricht unterstützen, ein Sprachcafé für eine kleine Gruppe leiten oder an einem Sprachaustausch teilnehmen.', 'noTranslation', '', '2025-11-01 20:51:21.29601', '2025-11-01 20:51:21.29601', 576, 19);
INSERT INTO public.opportunity VALUES (41, 'Begleitung und Sprachmittlung Sorani, Psychiatertermin', 'volunteering', '', 'englishOk', '', '2025-11-01 20:51:21.310295', '2025-11-01 20:51:21.310295', 577, 6);
INSERT INTO public.opportunity VALUES (42, 'Sportfest in Marzahn-Süd', 'volunteering', 'Wir brauchen Unterstützung durch Freiwillige, die an verschiedenen Sportstationen helfen, die Namen der Kinder aufzuschreiben, die an bestimmten Sportstationen teilnehmen möchten, oder die Kinder zu der Sportart führen, die sie suchen.', 'noTranslation', '', '2025-11-01 20:51:21.331272', '2025-11-01 20:51:21.331272', 578, 20);
INSERT INTO public.opportunity VALUES (43, 'Deutsch/Mathe Nachhilfe für neunte Klasse', 'volunteering', 'Wir suchen eine Person, die Einzelunterricht in Deutsch/Mathe geben könnte.', 'noTranslation', '', '2025-11-01 20:51:21.355466', '2025-11-01 20:51:21.355466', 579, 21);
INSERT INTO public.opportunity VALUES (44, 'Begleitung zur Geburtsanmeldung', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:21.372548', '2025-11-01 20:51:21.372548', 580, 5);
INSERT INTO public.opportunity VALUES (45, 'Unterstützung beim Sommerfest in Adlershof', 'volunteering', 'Wir suchen nach Freiwilligen, die uns beim Sommerfest unterstützen können.  Wir werden diesmal ohne Grill, aber mit Spielen für Kinder, Tanz und vielfältigem Essen aus verschiedenen Kulturen feiern.', 'noTranslation', '', '2025-11-01 20:51:21.406604', '2025-11-01 20:51:21.406604', 581, 22);
INSERT INTO public.opportunity VALUES (46, 'Kinderbetreuung: Basteln, Malen, Sport usw.', 'volunteering', 'Es gibt Kinder, die auch Arabisch, Georgisch, Tigrinisch und Armenisch sprechen. Sie sind von 6 bis 12 Jahre alt and die Freiwilligen sollen den Kinderbetreuer*innen helfen. Die Kinderbetreuung findet bis 18:30 Uhr statt.', 'noTranslation', '', '2025-11-01 20:51:21.438259', '2025-11-01 20:51:21.438259', 582, 23);
INSERT INTO public.opportunity VALUES (47, 'Organisiere unser Sprachcafé mit', 'volunteering', 'Mitorganisiere ein Sprachcafé für die Bewohner*innen der Unterkunft! Es findet immer donnerstags von 17 bis 19 Uhr statt.', 'noTranslation', '', '2025-11-01 20:51:21.476336', '2025-11-01 20:51:21.476336', 583, 24);
INSERT INTO public.opportunity VALUES (48, 'Begleitung - Doltmescher/*inn (Deutsch-Ukrainisch/Russisch)', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:21.494373', '2025-11-01 20:51:21.494373', 584, 9);
INSERT INTO public.opportunity VALUES (49, 'Kleiderkammer für Männer', 'volunteering', 'Unterstütze eine Kleiderkammer (von 13 bis 15 Uhr) durch Sortieren und Ausgeben von Kleidung.', 'noTranslation', '', '2025-11-01 20:51:21.510791', '2025-11-01 20:51:21.510791', 585, 24);
INSERT INTO public.opportunity VALUES (50, 'Kleiderkammer für Frauen und Kinder', 'volunteering', 'Unterstütze eine Kleiderkammer (von 13 bis 15 Uhr) durch Sortieren und Ausgeben von Kleidung.', 'noTranslation', '', '2025-11-01 20:51:21.526974', '2025-11-01 20:51:21.526974', 586, 24);
INSERT INTO public.opportunity VALUES (51, 'Bücher für Kinder vorlesen in Reinickendorf', 'volunteering', 'In der Unterkunft gibt es eine kleine Bibliothek mit Büchern in verschiedenen Sprachen. Es werden Freiwillige gesucht, die gerne für oder mit den Kindern Bücher lesen.
INSERT INTO public.opportunity VALUES (52, 'Begleitung zur Handchirugie', 'volunteering', '', 'englishOk', '', '2025-11-01 20:51:21.566014', '2025-11-01 20:51:21.566014', 588, 25);
INSERT INTO public.opportunity VALUES (53, 'Unterstützung gesucht: Sommerfest am 22.08.2025 – Ehrenamtliche für Grillen, Kochen oder Kinderaktionen gesucht', 'volunteering', 'Hallo zusammen,  für unser Sommerfest am 22.08.2025 von 15–18 Uhr suchen wir engagierte Ehrenamtliche, die Lust haben, uns zu unterstützen – z. B. beim Grillen, Kochen oder mit Kinderaktionen wie Basteln, Malen oder Spielen.  Ihr könnt euch gern nach euren Interessen einbringen – wir sind offen und flexibel.', 'noTranslation', '', '2025-11-01 20:51:21.595502', '2025-11-01 20:51:21.595502', 589, 2);
INSERT INTO public.opportunity VALUES (54, 'Übersetzung auf Farsi für Schulung!', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:21.611512', '2025-11-01 20:51:21.611512', 590, 21);
INSERT INTO public.opportunity VALUES (55, 'Sommerferien Betreuung mit Projekten und Ausflügen', 'volunteering', 'In den Sommerferien Kinderbetreuung Montag-Freitag mit Proketen den ganzen Tag oder Nachmittags (z.B. Malen, Basteln, Sport, Tanzen, Theater) und Ausflüge den ganzen Tag in Berlin (z.B. Sport, Zoo, Museum, Zirkus, Endeckungstouren).', 'noTranslation', '', '2025-11-01 20:51:21.651636', '2025-11-01 20:51:21.651636', 591, 26);
INSERT INTO public.opportunity VALUES (56, 'Alltagsbegleitung von Familie', 'volunteering', 'Wir suchen eine ehrenamtliche Person, die eine afghanische Familie im Alltag als Mentor:in unterstützen möchte. Die Familie wünscht sich eine:n Mentor:in, die:der Farsi oder Dari spricht und sie bei bürokratischen Angelegenheiten unterstützt sowie bei Terminen begleitet und ggf. übersetzten kann. Die Familie lebt mit 5 Kindern (6-21 Jahre) erst seit kurzer Zeit in Berlin. Da die Familie in verschiedenen Bereichen Unterstützung sucht, wird es noch eine zweite Mentorin geben mit der die Unterstützungsbereiche aufgeteilt werden können. Die Mentor:innenschaft wird durch das Team von XENION e.V. begleitet. Im XENION-Mentor:innenprogramm unterstützten ehrenamtliche Mentor:innen geflüchtete Einzelpersonen und Familien beim Ankommen in Berlin. Die Tandems treffen sich einmal die Woche für 2-3 Stunden, über den Zeitraum von einem Jahr. Wenn Du Interesse hast die Familie zu unterstützen und dich als Mentor:in zu engagieren, melde Dich gerne bei mailto:beeke.wattenberg@xenion.org !', 'noTranslation', '', '2025-11-01 20:51:21.673826', '2025-11-01 20:51:21.673826', 592, 27);
INSERT INTO public.opportunity VALUES (57, 'Sprachmittlung für Jobcenter-Termin', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:21.68692', '2025-11-01 20:51:21.68692', 593, 14);
INSERT INTO public.opportunity VALUES (58, 'Begleitung zur und Dolmetschen bei Mammografie', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:21.707742', '2025-11-01 20:51:21.707742', 594, 10);
INSERT INTO public.opportunity VALUES (59, 'Begleitung beim Einkaufen, Medikamente abholen etc.', 'volunteering', 'Im Rahmen unseres Projekts "Auf Achse" beim BZSL suchen wir freiwillige Unterstützer:innen für ein Ehepaar mit chronischer Erkrankung. Er sitz und bewegt sich im Rollstuhl und sie ist sehbehindert. Sie benötigen insbesondere Unterstützung beim Einkaufen und Abholen der Medikamente sowie ggf. bei anderen alltäglichen Aktivitäten. Sie sprechen Russisch, Georgisch und etwas Deutsch.', 'noTranslation', '', '2025-11-01 20:51:21.737065', '2025-11-01 20:51:21.737065', 595, 28);
INSERT INTO public.opportunity VALUES (60, 'Wegbegleitung zur Arztpraxis', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:21.750134', '2025-11-01 20:51:21.750134', 596, 26);
INSERT INTO public.opportunity VALUES (61, 'Freiwillige und Ehrenamtliche für BENN Mierendorffinsel', 'volunteering', 'Wir suchen nach Freiwilligen, die folgende Aktivitäten bei uns im WERK-RAUM und im Gemeinschaftsraum unterstützen möchten:
INSERT INTO public.opportunity VALUES (62, 'Sprachcafé', 'volunteering', 'Wir würden uns sehr freuen, wenn jemand Lust hätte, ein Sprachcafé anzubieten – der große Raum steht uns dafür zur Verfügung und bietet viel Platz für Begegnung und Austausch.', 'noTranslation', '', '2025-11-01 20:51:21.820559', '2025-11-01 20:51:21.820559', 598, 6);
INSERT INTO public.opportunity VALUES (63, 'Basteln für Kinder', 'volunteering', 'Wir suchen Unterstützung im Bereich Kinderbetreuung oder kreative Bastelangebote für Kinder im Alter von 2 bis 5 Jahren. Die Eltern sind in der Regel mit vor Ort, freuen sich aber sehr, wenn es für die Kleinen ein paar schöne Beschäftigungsmöglichkeiten gibt.', 'noTranslation', '', '2025-11-01 20:51:21.863383', '2025-11-01 20:51:21.863383', 599, 6);
INSERT INTO public.opportunity VALUES (64, 'Kinderschminken beim Sommerfest', 'volunteering', 'Wir suchen Freiwillige, die Kinderschminken als Aktion oder Angebot parallel zum Sommerfest kostenlos anbieten können.', 'noTranslation', '', '2025-11-01 20:51:21.88888', '2025-11-01 20:51:21.88888', 600, 18);
INSERT INTO public.opportunity VALUES (65, 'Begleitung zur Charité', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:21.912327', '2025-11-01 20:51:21.912327', 601, 30);
INSERT INTO public.opportunity VALUES (66, 'Begleitung zur Frauen Beratung', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:21.937332', '2025-11-01 20:51:21.937332', 602, 31);
INSERT INTO public.opportunity VALUES (67, 'Begleitung - Doltmescher/*inn (Deutsch-Ukrainisch/Russisch)', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:21.958101', '2025-11-01 20:51:21.958101', 603, 9);
INSERT INTO public.opportunity VALUES (68, 'Unterstützung beim Dolmetschen: Arzttermin', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:21.988659', '2025-11-01 20:51:21.988659', 604, 32);
INSERT INTO public.opportunity VALUES (69, 'Aktivitäten für männliche Geflüchtete (zum Beispiel Sprachkaffee, Sport, zusammen kochen und grillen) im Welcome Raum der Unterkunft.', 'volunteering', 'Bei der Unterkunft handelt es sich um eine Erstaufnahme Einrichtung für Geflüchtete, in der Unterkunft gibt es viel in der Kinderbetreuung und in der Betreuung von Frauen* aber grade junge Männer* fallen zurzeit ein bisschen aus dem Raster. In der Unterkunft gibt es einen Welcome Raum, mit einem Boxsack und einer Tischtennisplatte, es gibt ein großes Außengelände mit einem Fußballplatz und einer Grillmöglichkeit. Es gibt ein großes Team an Beschäftigten welche gerne unterstützen und zur Seite stehen. Wir freuen uns über Rückmeldungen.', 'noTranslation', '', '2025-11-01 20:51:22.025213', '2025-11-01 20:51:22.025213', 605, 33);
INSERT INTO public.opportunity VALUES (70, 'Yogakurs für Seniorinnen', 'volunteering', 'Biete einen Yogakurs an!', 'noTranslation', '', '2025-11-01 20:51:22.052417', '2025-11-01 20:51:22.052417', 606, 9);
INSERT INTO public.opportunity VALUES (71, 'Unterstützung beim Sommerfest', 'volunteering', 'Wir sind eine Erstaufnahmeeinrichtung für geflüchtete Familien in Biesdorf. Bei uns leben ca. 300 Bewohner aus unterschiedlichsten Ländern.  Am Freitag, den 29.08. zwischen 14-17 Uhr feiern wir unser erstes Sommerfest in der Unterkunft. Wir freuen uns über helfende Hände!', 'noTranslation', '', '2025-11-01 20:51:22.085881', '2025-11-01 20:51:22.085881', 607, 5);
INSERT INTO public.opportunity VALUES (72, 'Aktivitäten für Bewohner*innen gestalten', 'volunteering', 'Wir suchen nach Freiwilligen, die uns mit folgenden Aktivitäten unterstützen könnten:
INSERT INTO public.opportunity VALUES (73, 'Alltagsbegleitung durch ehrenamtliche Mentor*innen in Berlin Xenion', 'volunteering', 'Das Projekt wird vom psychosozialen Zentrum XENION im Rahmen eines ganzheitlichen Ansatzes umgesetzt. Die Ehrenamtlichen werden professionell durch das hauptamtliche Team betreut, können Schulungen und ein Aktivitätenprogramm besuchen und bei Bedarf eine Einzelsupervision in Anspruch..', 'noTranslation', '', '2025-11-01 20:51:22.154237', '2025-11-01 20:51:22.154237', 609, 34);
INSERT INTO public.opportunity VALUES (74, 'Unterstützung bei der Kinderbetreuung Sommerferien', 'volunteering', 'Wir suchen Freiwillige, die uns während der Sommerpause mit folgenden Aktivitäten unterstützen können:
INSERT INTO public.opportunity VALUES (75, 'Wohnungssuche Beratung vor Ort', 'volunteering', 'Die Bewohner*innen brauchen Unterstützung bei der Wohnungssuche. Es geht um Fragen wie:    Wo und wie beantragt man einen WBS (Wohnberechtigungsschein)?
INSERT INTO public.opportunity VALUES (76, 'Sportunterricht für Kinder in Marienfelde', 'volunteering', 'Es wäre ideal, wenn die Freiwillige Deutsch sprechen, da die Kinder es lernen sollen. Das ganze Team spricht Russisch.', 'noTranslation', '', '2025-11-01 20:51:22.231791', '2025-11-01 20:51:22.231791', 612, 35);
INSERT INTO public.opportunity VALUES (77, 'Dolmetschen im Virchow Klinikum', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.249132', '2025-11-01 20:51:22.249132', 613, 10);
INSERT INTO public.opportunity VALUES (78, 'Individuelle Vorbereitung für Deutschprüfungen', 'volunteering', 'Unterstütze erwachsene Bewohner*innen bei der Vorbereitung für Deutschprüfungen (A2-B2)', 'noTranslation', '', '2025-11-01 20:51:22.273564', '2025-11-01 20:51:22.273564', 614, 36);
INSERT INTO public.opportunity VALUES (79, 'Deutschnachhilfe / Lernen A1 (Individuell für mobilitätseingschränkte Person)', 'volunteering', 'Victor ist neu in die GU Osteweg gezogen, zuvor hat er in Mitte gewohnt. Er ist durch eine chronische Erkrankung mobilitätseingeschränkt, weshalb er nicht an allen Deutschkursen teilnehmen kann. Daher suchen wir eine Person, die ihn individuell im Osteweg beim Deutschlernen unterstützen kann. Er hat den A1 Kurs schon abgeschlossen und ist mitten im Niveau A2.1. Er ist zeitlich flexibel. Im Osteweg gibt es einen Hausaufgabenraum mit Tafel und Computern, die gern genutzt werden können oder man trifft sich bei Victor in der Wohnküche.Victor spricht Englisch und Igbo muttersprachlich und ist 43 Jahre alt.', 'noTranslation', '', '2025-11-01 20:51:22.301046', '2025-11-01 20:51:22.301046', 615, 36);
INSERT INTO public.opportunity VALUES (80, 'Nachhilfe alle Klassenstufen für die Fächer Deutsch, Mathe, Englisch', 'volunteering', 'Wir suchen jemand mit Interesse an Nachhilfe mit Fokus auf Deutsch, Mathe, Englisch. Falls jemand aber lieber zu, Beispiel eine Lesegruppe oder Gruppen-Nachhilfe machen möchte, ist das auch möglich.', 'noTranslation', '', '2025-11-01 20:51:22.31806', '2025-11-01 20:51:22.31806', 616, 36);
INSERT INTO public.opportunity VALUES (81, 'Unterstütze mit Kinderbetreuung in Mitte', 'volunteering', 'Am besten wäre es, wenn die Freiwilligen jeweils 2-3 Stunden mitarbeiten könnten. Es wäre toll, wenn sie regelmäßig kommen könnten.', 'noTranslation', '', '2025-11-01 20:51:22.340187', '2025-11-01 20:51:22.340187', 617, 30);
INSERT INTO public.opportunity VALUES (82, 'Unterstützung bei Begegnungsformaten wie Nachbarschaftstreff, Café Palme oder Gartengruppe', 'volunteering', 'Wir begleiten momentan drei Begegnungsformate in Unterkünften bzw. mit BewohnerInnen der Unterkünfte in Altglienicke. Wir suchen Freiwillige, die unsere Arbeit unterstützen. Das ist in vielfältiger Weise möglich..In den Café Formaten kann gemeinam Deutsch gelernt werden, gemeinam Kuchen gebacken und international gekocht werden, wir tanzen manchmal, spielen Schach, hören uns gegenseitig zu.. Die Gartengruppe kümmert sich um die Grünanlagen in den Einrichtungen in Altglienicke wie Cabuwazi und Kiezclub. Wir pflanzen und pflegen naturnahe Orte, bauen Hochbeete und lernen gleich noch bisschen Deutsch dabei :)', 'noTranslation', '', '2025-11-01 20:51:22.395172', '2025-11-01 20:51:22.395172', 618, 37);
INSERT INTO public.opportunity VALUES (83, 'Begleitung zu einem Termin beim Jobcenter Spandau', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.424102', '2025-11-01 20:51:22.424102', 619, 38);
INSERT INTO public.opportunity VALUES (84, 'Dolmetschen beim Jobcenter', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.453591', '2025-11-01 20:51:22.453591', 620, 39);
INSERT INTO public.opportunity VALUES (85, 'Begleitung zum Arzt/Neurologe', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.46946', '2025-11-01 20:51:22.46946', 621, 3);
INSERT INTO public.opportunity VALUES (86, 'Begleitung zum Arzt', 'volunteering', '', 'englishOk', '', '2025-11-01 20:51:22.485458', '2025-11-01 20:51:22.485458', 622, 3);
INSERT INTO public.opportunity VALUES (87, 'Begleitung zum Ferienprogramm', 'volunteering', 'Zwei Wochen ab dem 4.8.2025. Um 8:30 Uhr abholen und zum Schul-Umwelt-Zentrum, begleiten dann wieder am Nachmittag (gegen 15 Uhr) zurück. Es ist eine Gruppe von 10 Kindern und sie werden schon von einer Mitarbeiterin begleitet aber sie brauchen nur eine Person.', 'noTranslation', '', '2025-11-01 20:51:22.509049', '2025-11-01 20:51:22.509049', 623, 30);
INSERT INTO public.opportunity VALUES (88, 'Übersetzung ins Russisch beim Arzttermin für Internist', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.538865', '2025-11-01 20:51:22.538865', 624, 40);
INSERT INTO public.opportunity VALUES (89, 'Dolmetschen beim Arzt', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.555796', '2025-11-01 20:51:22.555796', 625, 10);
INSERT INTO public.opportunity VALUES (90, 'Sprachmittlung Georgisch psychologische Beratung', 'volunteering', 'In den beiden Unterkünften in Charlottenburg, gibt es einen hohen Bedarf von Menschen, die Georgisch sprechen und psychologische Beratung wünschen, SprInt hat aber nur sehr wenige Kapazitäten und Gespräche können darum nur in sehr großen Abständen und mit langer Wartezeit stattfinden. Darum frage ich an, ob eine Person, die Georgisch spricht sich vorstellen könnte gelegentlich zu übersetzen.', 'noTranslation', '', '2025-11-01 20:51:22.576887', '2025-11-01 20:51:22.576887', 626, 6);
INSERT INTO public.opportunity VALUES (91, 'Arzt Begleitung', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.592843', '2025-11-01 20:51:22.592843', 627, 6);
INSERT INTO public.opportunity VALUES (92, 'Begleitung zur Charité', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.613549', '2025-11-01 20:51:22.613549', 628, 6);
INSERT INTO public.opportunity VALUES (93, 'Unterstützung beim Sommerfest', 'volunteering', 'Kinderschminke, Hüpfburg, Basteln, Essenausgabe, Auf-Abbau', 'noTranslation', '', '2025-11-01 20:51:22.634994', '2025-11-01 20:51:22.634994', 629, 4);
INSERT INTO public.opportunity VALUES (94, 'OP Vorbereitung - HNO', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.652324', '2025-11-01 20:51:22.652324', 630, 6);
INSERT INTO public.opportunity VALUES (95, 'Dolmetschen beim Aufnahmezentrum zur stationären Behandlung', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.670045', '2025-11-01 20:51:22.670045', 631, 36);
INSERT INTO public.opportunity VALUES (96, 'Dolmetschen Russisch im Krankenhaus', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.691323', '2025-11-01 20:51:22.691323', 632, 10);
INSERT INTO public.opportunity VALUES (97, 'Unterstützung beim Abbau des Sommerfests', 'volunteering', 'Wir suchen Unterstützung beim Aubbau unseres Sommerfests am Freitag, 11.07.25 zwischen 18-19:30 Uhr. Natürlich sind die Helfenden herzlich eingeladen auch schon ab 15 Uhr zum Fest zu kommen. Für das leibliche Wohl (Getränke, Grillgut, Kuchen) ist gesorgt. Wir freuen uns über tatkräftige Unterstützung :)', 'noTranslation', '', '2025-11-01 20:51:22.727015', '2025-11-01 20:51:22.727015', 633, 41);
INSERT INTO public.opportunity VALUES (98, 'Unterstützung beim Aufbau des Sommerfests', 'volunteering', 'Wir suchen Unterstützung beim Aufbau unseres Sommerfests (Dekorieren, Aufstellen von Tischen, Grill, Vorbereitung von Getränken) am Freitag, 11.07.25 zwischen 12-15 Uhr. Natürlich sind die Helfenden herzlich eingeladen auch noch zum Fest zu bleiben. Für das leibliche Wohl (Getränke, Grillgut, Kuchen) ist gesorgt. Wir freuen uns über tatkräftige Unterstützung :)', 'noTranslation', '', '2025-11-01 20:51:22.751239', '2025-11-01 20:51:22.751239', 634, 41);
INSERT INTO public.opportunity VALUES (99, 'Sprachmittlung Spanisch', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.772851', '2025-11-01 20:51:22.772851', 635, 6);
INSERT INTO public.opportunity VALUES (100, 'Begleitung zum Standesamt', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.789816', '2025-11-01 20:51:22.789816', 636, 5);
INSERT INTO public.opportunity VALUES (101, 'Sprachliche Hilfe bei Eltern- und Schülerinnengespräch mit Lehrkraft', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.817341', '2025-11-01 20:51:22.817341', 637, 42);
INSERT INTO public.opportunity VALUES (102, 'Sprachmittlung beim Gespräch mit dem Sozialteam', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.834081', '2025-11-01 20:51:22.834081', 638, 2);
INSERT INTO public.opportunity VALUES (103, 'Russisch Dolmetschen bei Arzttermin', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.853014', '2025-11-01 20:51:22.853014', 639, 10);
INSERT INTO public.opportunity VALUES (104, 'Übersetzen beim Arzttermin', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.878157', '2025-11-01 20:51:22.878157', 640, 1);
INSERT INTO public.opportunity VALUES (105, 'Unterstützung beim Sommerfest', 'volunteering', 'Unser Fest findet am 04.07. zwischen 14 und 18 Uhr statt und wir suchen aktuell zu diesem Anlass ehrenamtliche Unterstützung für Kinderangebote (Kreatives, Sport/Bewegung, Kinderschminken/Tattoos, Luftballontiere etc.), Hilfe beim Auf- und Abbau sowie während des Fests und darüber hinaus auch Angebote für Erwachsene (Zeichnen, Handarbeit etc.). Wir sind für alles offen und freue mich über engagierte Ehrenamtliche, die gerne auch ihre eigenen Ideen mitbringen und umsetzen können!', 'noTranslation', '', '2025-11-01 20:51:22.914544', '2025-11-01 20:51:22.914544', 641, 43);
INSERT INTO public.opportunity VALUES (106, 'Dolmetscher für Termin für MRT', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.941954', '2025-11-01 20:51:22.941954', 642, 44);
INSERT INTO public.opportunity VALUES (107, 'Einschulungsuntersuchung', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:22.969332', '2025-11-01 20:51:22.969332', 643, 45);
INSERT INTO public.opportunity VALUES (108, 'Begleitung für Ausflüge', 'volunteering', 'Wir suchen Ehrenamtliche, die die Kinderbetreuung für 2-3 Stunden nachmittags bei Ausflügen unterstützen.  In der Nähe gibt es Spielplätz, Kindermuseen, Parks und Freizeitangebote.', 'noTranslation', '', '2025-11-01 20:51:23.007654', '2025-11-01 20:51:23.007654', 644, 46);
INSERT INTO public.opportunity VALUES (109, 'Freizeitaktivitäten- und/oder Freizeitangebote für Frauen', 'volunteering', 'Ziel ist es, den Frauen, die in der GU im Kaklower Weg leben (alle mit kleinen Kindern), jede Art von Freizeitbeschäftigung anzubieten. Es wäre ideal, einmal pro Woche, aber ich bleibe zu Ihrer vollen Verfügung für jede Beratung.', 'noTranslation', '', '2025-11-01 20:51:23.029048', '2025-11-01 20:51:23.029048', 645, 16);
INSERT INTO public.opportunity VALUES (110, 'Musikalische Darbietung am Tag des Sommerfestes', 'volunteering', 'Es kann gerne auch eine Musikgruppe oder eine Tanzgruppe sein, wir haben ein Budget von 250 EUR zur Verfügung. Vielen Dank!', 'noTranslation', '', '2025-11-01 20:51:23.062747', '2025-11-01 20:51:23.062747', 646, 47);
INSERT INTO public.opportunity VALUES (111, 'Basteln & Malen', 'volunteering', 'Kreative Nachmittagsaktivitäten für Kinder bis zu 14 Jahren. Gemeinsam malen und/oder basteln. Ein Nachmittag pro Woche nach Ihrer Wahl (je nach ihrer Verfügbarkeit) am Montag, Mittwoch oder Donnerstag,  in unserer GU im Kablower Weg 89 - 12526 Berlin.', 'noTranslation', '', '2025-11-01 20:51:23.088594', '2025-11-01 20:51:23.088594', 647, 16);
INSERT INTO public.opportunity VALUES (112, 'Begleitung von Kindern im Jugendclub', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.106429', '2025-11-01 20:51:23.106429', 648, 48);
INSERT INTO public.opportunity VALUES (113, 'Sprachmittlung Französisch', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.128942', '2025-11-01 20:51:23.128942', 649, 49);
INSERT INTO public.opportunity VALUES (114, 'Jobcenter begleitung', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.151871', '2025-11-01 20:51:23.151871', 650, 50);
INSERT INTO public.opportunity VALUES (115, 'Begleitung bei alltäglichen Aktivitäten, Unterstützung beim Deutsch lernen', 'volunteering', 'Im Rahmen unseres Projekts „Auf Achse“ suchen wir ehrenamtliche Unterstützung für einen Mann aus Kamerun mit einer Sehbehinderung. Er wohnt in Köpenick und spricht Französisch, ein bisschen Englisch und hat begonnen Deutsch zu lernen. Er benötigt Hilfe bei alltäglichen Aktivitäten wie Einkaufen, Haushalt organisieren oder einmaligen Aktivitäten wie das Einrichten der Wohnung. Zudem würde er sich über Unterstützung beim Deutsch lernen freuen.', 'noTranslation', '', '2025-11-01 20:51:23.178908', '2025-11-01 20:51:23.178908', 651, 51);
INSERT INTO public.opportunity VALUES (116, 'Begleitung zur Schuluntersuchung beim Bezirksamt', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.207652', '2025-11-01 20:51:23.207652', 652, 52);
INSERT INTO public.opportunity VALUES (117, 'Sport mit Jungs (9-13 Jahre)', 'volunteering', 'Wir suchen männliche Ehrenamtliche, die 2-3 Stunden nachmittags bei sportlichen Aktivitäten unterstützen. In unserer Unterkunft gibt es einen Kinderraum, einen großen Innenhof mit Garten und in der Nähe Spielplätze und Freizeitangebote.', 'noTranslation', '', '2025-11-01 20:51:23.240336', '2025-11-01 20:51:23.240336', 653, 46);
INSERT INTO public.opportunity VALUES (118, 'Nachhilfe für Kinder, bei Möglichkeit auch für Jugendliche', 'volunteering', 'Es kann auch ein Nachmittag in der Woche sein, da wir hierfür flexibel sind haben wir Tage die in Frage kommen markiert.', 'noTranslation', '', '2025-11-01 20:51:23.271118', '2025-11-01 20:51:23.271118', 654, 47);
INSERT INTO public.opportunity VALUES (119, 'Kinderbetreuung', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.288101', '2025-11-01 20:51:23.288101', 655, 46);
INSERT INTO public.opportunity VALUES (120, 'Begleitung zur Innere Medizin/ Internist', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.315203', '2025-11-01 20:51:23.315203', 656, 53);
INSERT INTO public.opportunity VALUES (121, 'Begleitung zum Spielplatz oder Kolle 8 und zurück, Sport und Bewegungsangebot', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.344455', '2025-11-01 20:51:23.344455', 657, 54);
INSERT INTO public.opportunity VALUES (122, 'Begleitung und Betreuung von 5 Kindern (5-7 Jahre) in die Bibliothek am Wasserturm', 'volunteering', 'Wir brauchen eine(n) Frewilligen, der/die die Kinder jeden zweiten Mittwoch zwischen 16:30 und 18:30 von der Unterkunft in die Bibliothek und zurück begleitet und die Kinder während des Angebots ("Podesthelden" und "ABC-Piraten") betreut.', 'noTranslation', '', '2025-11-01 20:51:23.362976', '2025-11-01 20:51:23.362976', 658, 54);
INSERT INTO public.opportunity VALUES (123, 'Begleitung zur Bank', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.381105', '2025-11-01 20:51:23.381105', 659, 53);
INSERT INTO public.opportunity VALUES (124, 'Aktivitäten für Männer in Neukölln gestalten', 'volunteering', 'Ankommen, Verstehen, Teilhaben. Gemeinsam neue Wege gehen: Männerprojekt von GBZ e.V.  Geflüchtete Männer in Berlin stehen vor vielfältigen Herausforderungen: das Verstehen gesellschaftlicher Normen, Integrationshürden oder das Gefühl von Isolation. Genau hier setzt unser Männerprojekt an. Es schafft einen geschützten Raum für Orientierung, Austausch und Bildung – mit dem Ziel, gesellschaftliche Teilhabe zu erleichtern und neue Perspektiven zu eröffnen.', 'noTranslation', '', '2025-11-01 20:51:23.418388', '2025-11-01 20:51:23.418388', 660, 55);
INSERT INTO public.opportunity VALUES (125, 'Begleitung zu MVZ Radiologie', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.436008', '2025-11-01 20:51:23.436008', 661, 10);
INSERT INTO public.opportunity VALUES (126, 'Begleitung zum Auguste Viktoria Klinikum', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.454606', '2025-11-01 20:51:23.454606', 662, 7);
INSERT INTO public.opportunity VALUES (127, 'Organisiere Spiele für Kinder im Spielraum in Neukölln', 'volunteering', 'Sprachen sind kein Muss, aber die meisten im Team sprechen Deutsch.
INSERT INTO public.opportunity VALUES (128, 'Sitzbank-Reparatur', 'volunteering', 'Unterstützung bei der Reparatur der Paletten-Sitzbank. Ehrenamtliche, die Kenntnisse mit Holz haben, wären ideal. Bewohnenden  werden bei der Tätigkeit unterstützen. Wir haben einige extra Paletten in der Unterkunft, die für die Aktion genutzt werden können.  Danke für Ihre Hilfe und Unterstützung.', 'noTranslation', '', '2025-11-01 20:51:23.505953', '2025-11-01 20:51:23.505953', 664, 20);
INSERT INTO public.opportunity VALUES (129, 'Unterstützung in der Ferienzeit', 'volunteering', 'Unterstützung von Ehrenamtlichen während der Ferienzeit. Gibt es im Hinterhaus der Unterkunft einen Spielplatz. Wenn Sie einen Freiwilligen finden könnten, der die Kinder dorthin bringt und mit ihnen Sport treibt, oder einen Freiwilligen, der mit den Kindern nicht-sportliche Aktivitäten unternimmt. Zu den nicht-sportlichen Aktivitäten gehört die Betreuung der Kinder in der Kita. Vorlesen oder jemand, der Interesse an Aktivitäten während der Ferienzeit hat.', 'noTranslation', '', '2025-11-01 20:51:23.532567', '2025-11-01 20:51:23.532567', 665, 20);
INSERT INTO public.opportunity VALUES (130, 'Aktivitäten für ein Frauen*café', 'volunteering', 'Unterstütze das Team einer Unterkunft bei der Einrichtung eines Frauenraums für Geflüchtete, der den Interessen der Bewohnerinnen entspricht. Sie wollen einen Ort des Kennenlernens und des kulturellen Austauschs schaffen, an dem sich die Frauen sicher fühlen und den Raum nach Belieben nutzen können.', 'noTranslation', '', '2025-11-01 20:51:23.560055', '2025-11-01 20:51:23.560055', 666, 7);
INSERT INTO public.opportunity VALUES (131, 'Begleitung zum Standesamt', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.576366', '2025-11-01 20:51:23.576366', 667, 18);
INSERT INTO public.opportunity VALUES (132, 'Begleitung/Übersetzung deutsch', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.592405', '2025-11-01 20:51:23.592405', 668, 18);
INSERT INTO public.opportunity VALUES (133, 'Sprachmittlung in Unterkunft Urhobo', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.610194', '2025-11-01 20:51:23.610194', 669, 6);
INSERT INTO public.opportunity VALUES (134, 'Erstorientierung für eine arabischsprachige Frau', 'volunteering', 'Wir suchen im Moment eine arabischsprachige Ehrenamtliche, die gelegentlich eine tunesische Bewohnerin begleiten könnte, für sie gegebenenfalls übersetzen würde und ihr Dinge wie das Ticketlösen etc. zeigt. Die Bewohnerin hat frisch entbunden, spricht noch keinerlei Deutsch und hat noch jede Menge bürokratisch und sozial vor sich. Wir würden uns sehr freuen, wenn sich für sie jemand findet, der Lust auf eine Eins-zu-Eins-Betreuung hat!', 'noTranslation', '', '2025-11-01 20:51:23.62736', '2025-11-01 20:51:23.62736', 670, 43);
INSERT INTO public.opportunity VALUES (135, 'Übersetzung ins Russisch beim Zahnarzttermin', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.648945', '2025-11-01 20:51:23.648945', 671, 40);
INSERT INTO public.opportunity VALUES (136, 'Hilfe bei den Hausaufgaben für Grundschüler*innen in Wilmersdorf', 'volunteering', 'Es handelt sich um eine regelmäßige Freiwilligenarbeit (einmal pro Woche). Es wird Unterstützung für Grundschulkinder in verschiedenen Fächern benötigt. Die Kinder sprechen Deutsch, also sollte der Freiwillige auch Deutsch sprechen können.', 'noTranslation', '', '2025-11-01 20:51:23.666883', '2025-11-01 20:51:23.666883', 672, 56);
INSERT INTO public.opportunity VALUES (137, 'Frauenarzt', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.680918', '2025-11-01 20:51:23.680918', 673, 53);
INSERT INTO public.opportunity VALUES (138, 'Überzetzung/Begleitung beim Termin mit dem Psychologe', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.696035', '2025-11-01 20:51:23.696035', 674, 3);
INSERT INTO public.opportunity VALUES (139, 'Verantwortliche für Kleiderkammer', 'volunteering', 'Wir suchen engagierte Freiwillige, die unsere Kleiderkammer in der Aufnahmeeinrichtung unterstützen möchten.  
INSERT INTO public.opportunity VALUES (140, 'Sprachmittlung Georgisch und Russisch', 'volunteering', 'Die Bewohner*innen der Unterkunft benötigen dringend Unterstützung bei Übersetzungen (Georgisch/Russisch - Englisch/Deutsch).', 'noTranslation', '', '2025-11-01 20:51:23.741382', '2025-11-01 20:51:23.741382', 676, 57);
INSERT INTO public.opportunity VALUES (141, 'Farsi Übersetzung im Standesamt Reinickendorf für Geburtsanmeldung am 19:05 um 12:00', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.758369', '2025-11-01 20:51:23.758369', 677, 10);
INSERT INTO public.opportunity VALUES (142, 'Nachhilfe in Englisch und Deutsch: Anfängerniveu, Einzel- oder Gruppenunterricht', 'volunteering', 'Hallo, wir suchen Nachhilfe in Englisch, Deutsch und allgemein Hausaufgabenhilfe auf relativ einfachem Niveau. Es gibt einzelne Kinder und junge Erwachsene, die selbst Nachhilfe suchen aber auch Eltern, die für ihre Kinder Nachhilfe suchen. Teilweise wäre Einzelunterricht nötig oder aber auch ein offenes Nachhilfeangebot in einem unserer Clubräume.', 'noTranslation', '', '2025-11-01 20:51:23.785418', '2025-11-01 20:51:23.785418', 678, 58);
INSERT INTO public.opportunity VALUES (143, 'Begleitung- Hörgerateversorgung (Voruntersuchung)', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.806099', '2025-11-01 20:51:23.806099', 679, 32);
INSERT INTO public.opportunity VALUES (144, 'Unterstütze bei Kinderbetreuung in Zehlendorf', 'volunteering', 'Freiwillige werden zur Unterstützung des Kinderbetreuungspersonals benötigt (Organisation von Aktivitäten, Einbringen neuer Ideen, Unterstützung bei bestehenden Aktivitäten wie Spielen und Basteln)', 'noTranslation', '', '2025-11-01 20:51:23.831123', '2025-11-01 20:51:23.831123', 680, 58);
INSERT INTO public.opportunity VALUES (145, 'Ausflüge für Familien', 'volunteering', 'Unterstützung bei der Organisation von Ausflügen und Freizeitaktivitäten außerhalb der Unterkunft für die dort lebenden Familien.', 'noTranslation', '', '2025-11-01 20:51:23.851954', '2025-11-01 20:51:23.851954', 681, 4);
INSERT INTO public.opportunity VALUES (146, 'Sprachcafé für Bewohner*innen', 'volunteering', 'Wir suchen nach Freiwilligen mit fortgeschrittenen Deutschkenntnissen, die die Bewohner*innen der Unterkunft Deutsch beibringen möchten.', 'noTranslation', '', '2025-11-01 20:51:23.873272', '2025-11-01 20:51:23.873272', 682, 9);
INSERT INTO public.opportunity VALUES (147, 'Begleitung zum  Orthopädietechnik', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.88807', '2025-11-01 20:51:23.88807', 683, 53);
INSERT INTO public.opportunity VALUES (148, 'Unterstützung mit Übersetzungen für Sozialarbeiter*innen', 'volunteering', 'Unterstützung der Sozialarbeiter*innen bei Übersetzungen während der Beratungsstunden.', 'noTranslation', '', '2025-11-01 20:51:23.906492', '2025-11-01 20:51:23.906492', 684, 19);
INSERT INTO public.opportunity VALUES (149, 'Hausaufgabenhilfe', 'volunteering', 'Wir suchen Ehrenamtliche für die Hausaufgabenhilfe in unserer Gemeinschaftsunterkunft.', 'noTranslation', '', '2025-11-01 20:51:23.93387', '2025-11-01 20:51:23.93387', 685, 59);
INSERT INTO public.opportunity VALUES (150, 'Telefondienst', 'volunteering', 'Wir suchen Ehrenamtliche, die Spaß am Telefonieren haben und in unserer Einrichtung Anrufe entgegennehmen und weiterleiten.', 'noTranslation', '', '2025-11-01 20:51:23.95117', '2025-11-01 20:51:23.95117', 686, 59);
INSERT INTO public.opportunity VALUES (151, 'Begleitung HNO-Klinik - Op Voruntersuchung', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:23.966559', '2025-11-01 20:51:23.966559', 687, 6);
INSERT INTO public.opportunity VALUES (152, 'Unterstütze ein Sprachcafé und ein Männer*café', 'volunteering', 'Wir suchen Ehrenamtliche, die Lust haben, das Männercafé mitzugestalten und sich dort zu engagieren. Außerdem wollen wir gemeinsam das Konzept entwickeln und kreative Ideen austauschen.', 'noTranslation', '', '2025-11-01 20:51:24.003118', '2025-11-01 20:51:24.003118', 688, 60);
INSERT INTO public.opportunity VALUES (153, 'Sprachtandem in Neukölln', 'volunteering', 'Bewohner*innen der Gemeinschaftsunterkunft möchten ihre Deutschkenntnisse verbessern. Sie sind an einem Deutschkurs interessiert und würden gerne daran teilnehmen.', 'noTranslation', '', '2025-11-01 20:51:24.018373', '2025-11-01 20:51:24.018373', 689, 60);
INSERT INTO public.opportunity VALUES (154, 'Begleitung zu Behördengängen und  Arztterminen', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:24.029173', '2025-11-01 20:51:24.029173', 690, 53);
INSERT INTO public.opportunity VALUES (155, 'Unterstützung bei der Gartenarbeit (Gemüsegarten)', 'volunteering', 'Es gibt einen kleinen Gemüsegarten im Hof, und die Mitarbeiter*innen würden sich über die Unterstützung einer Person freuen, die sich mit dem Gärtnern auskennt. Die Gartensaison wäre etwa Mitte Oktober zu Ende.', 'noTranslation', '', '2025-11-01 20:51:24.054444', '2025-11-01 20:51:24.054444', 691, 28);
INSERT INTO public.opportunity VALUES (156, 'Kinderarzt Begleitung', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:24.068864', '2025-11-01 20:51:24.068864', 692, 26);
INSERT INTO public.opportunity VALUES (157, 'Nachhilfe bei der Ausbildung', 'volunteering', 'Gesucht wird eine Frau, die einer Frau Nachhilfe bei der Ausbildung zur Sozialassistentin gibt.', 'noTranslation', '', '2025-11-01 20:51:24.096158', '2025-11-01 20:51:24.096158', 693, 61);
INSERT INTO public.opportunity VALUES (158, 'Lebenslauf schreiben', 'volunteering', '.', 'noTranslation', '', '2025-11-01 20:51:24.117522', '2025-11-01 20:51:24.117522', 694, 17);
INSERT INTO public.opportunity VALUES (159, 'Nähkurs für Jugendliche', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:24.139155', '2025-11-01 20:51:24.139155', 695, 17);
INSERT INTO public.opportunity VALUES (160, 'Organisiere Aktivitäten für Frauen', 'volunteering', 'Wir suchen Freiwillige, die Aktivitäten für Frauen organisieren möchten, z.B. Yoga, Tanzen, Musik usw.', 'noTranslation', '', '2025-11-01 20:51:24.166896', '2025-11-01 20:51:24.166896', 696, 62);
INSERT INTO public.opportunity VALUES (161, 'Nachhilfe für Kinder und Jugendliche', 'volunteering', 'Unterstütze Kinder, die in einer Gemeinschaftsunterkunft leben, mit Nachhilfeunterricht!', 'noTranslation', '', '2025-11-01 20:51:24.193808', '2025-11-01 20:51:24.193808', 697, 63);
INSERT INTO public.opportunity VALUES (162, 'Unterstütze mit Kinderbetreuung in Prenzlauer Berg', 'volunteering', 'Organisiere spannende Aktivitäten für Kinder und unterstütze sie beim Basteln.', 'noTranslation', '', '2025-11-01 20:51:24.217864', '2025-11-01 20:51:24.217864', 698, 40);
INSERT INTO public.opportunity VALUES (163, 'Unterstütze mit Kinderbetreuung in Grünau', 'volunteering', 'Plane und organisiere Bastelaktivitäten für Kinder in einer Unterkunft in Grünau.', 'noTranslation', '', '2025-11-01 20:51:24.237797', '2025-11-01 20:51:24.237797', 699, 16);
INSERT INTO public.opportunity VALUES (164, 'Nachhilfe in Lichtenberg', 'volunteering', 'Unterstütze Kinder, die in der Gemeinschaftsunterkunft leben, mit Nachhilfeunterricht!', 'noTranslation', '', '2025-11-01 20:51:24.255799', '2025-11-01 20:51:24.255799', 700, 19);
INSERT INTO public.opportunity VALUES (165, 'Organisiere Kinderbetreuung in Lichtenberg', 'volunteering', 'Unterstütze beim Aufbau einer Kinderbetreuung und organisiere lustige Aktivitäten für Kinder, die in einer Unterkunft in Lichterberg leben. Es gibt dort noch keine offizielle Kinderbetreuung, so dass die Freiwilligen selbst für die Organisation der Aktivitäten verantwortlich sind.', 'noTranslation', '', '2025-11-01 20:51:24.273234', '2025-11-01 20:51:24.273234', 701, 19);
INSERT INTO public.opportunity VALUES (166, 'Organisiere Aktivitäten für Kinder in Tempelhof', 'volunteering', 'Organisiere lustige Spiele und andere Aktivitäten für Kinder (ab 7 Jahren), die in einer Unterkunft in Tempelhof leben. Die Zeiten für die Freiwilligenarbeit können individuell besprochen werden.', 'noTranslation', '', '2025-11-01 20:51:24.285902', '2025-11-01 20:51:24.285902', 702, 24);
INSERT INTO public.opportunity VALUES (167, 'Sportunterricht für die Bewohner*innen', 'volunteering', 'Die Bewohner*innen der Unterkunft würden gerne mit Freiwilligen Fußball, Volleyball, Tischtennis und andere Spiele spielen. Der Zeitplan ist flexibel und kann mit der Ehrenamtskoordination abgesprochen werden.', 'noTranslation', '', '2025-11-01 20:51:24.314864', '2025-11-01 20:51:24.314864', 703, 33);
INSERT INTO public.opportunity VALUES (168, 'Organisiere Kinderbetreuung in Lichtenberg', 'volunteering', 'Montag haben wir leider keine eigene Betreuung und bräuchten da eigentlich sehr dringend Hilfe. Das ließe sich aber wegen des 4 AugenPrinzips nur lösen wenn wir über Euch gleich 2 Ehrenamtliche bekämen die zeitgleich könnten.Sprachlich wäre Deutsch als Basis vor allem für die Hausaufgabenbetreuung wichtig. Ansonsten haben wir Kinder, die arabisch, farsi, russisch georgisch etc sprechen- da wäre alles natürlich hilfreich aber nicht Voraussetzung.', 'noTranslation', '', '2025-11-01 20:51:24.341265', '2025-11-01 20:51:24.341265', 704, 2);
INSERT INTO public.opportunity VALUES (169, 'Sei Teil des Hürdenspringers in Tempelhof-Schöneberg', 'volunteering', 'Es handelt sich um ein langfristiges Programm, das eine ernsthafte Entwicklung der Freiwilligen erfordert.', 'noTranslation', '', '2025-11-01 20:51:24.363135', '2025-11-01 20:51:24.363135', 705, 64);
INSERT INTO public.opportunity VALUES (170, 'Unterstütze mit Kinderbetreuung in Tegel', 'volunteering', 'Sie brauchenFreiwillige, die Aktivitäten für die Kinder organisiert und die Kinderbetreuer*innen unterstützt. Da es sich um eine Erstaufnahmeeinrichtung handelt, gehen einige der Kinder noch nicht zur Schule, so dass die Hilfe auch am Vormittag benötigt werden könnte.
