INSERT INTO public.opportunity VALUES (172, 'Kinderaktivitäten gestalten', 'volunteering', 'Eigeninitiative und erste Erfahrungen in der Arbeit mit Kindern notwendig, da relativ große Altersspanne. Das Angebot findet im Garten am Montag zw. 16 und 18 Uhr statt.', 'noTranslation', '', '2025-11-01 20:51:24.438054', '2025-11-01 20:51:24.438054', 708, 7);
