INSERT INTO public.opportunity VALUES (193, 'Sprachmittlung Russisch während Sprechstunde im Unterkunft', 'volunteering', 'Wir brauchen bitte Sprachmittlung Unterstützung für unsere russischsprachigen Bewohner*innen. Unsere russischsprachige Sozialarbeiterin ist vom 14. bis 25. April im Urlaub. Die Sprechstunden findet nur montags, dienstags, donnerstags und freitags von 10 bis 12Uhr und montags, dienstags und donnerstags von 14-16Uhr statt. Auch hier freuen wir für jede Zeit und jedes Datum, das möglich ist; wir würden diese Unterstützung sehr zu schätzen wissen. Vielen Dank im Voraus!', 'noTranslation', '', '2025-11-01 20:51:24.85115', '2025-11-01 20:51:24.85115', 729, 3);
