INSERT INTO public.opportunity VALUES (199, 'Unterstütze bei der Wohnungssuche', 'volunteering', 'Wir haben mehrere Bewohner*innen, die gerne Hilfe hätten, wie man sich selbst eine eigene Wohnung sucht (wo sucht man, welche Unterlagen muss ich vorbereiten/beantragen, wie mache ich eine Bewerbung, was nehme ich mit zur Wohnungsbesichtigung etc.', 'noTranslation', '', '2025-11-01 20:51:24.98025', '2025-11-01 20:51:24.98025', 735, 66);
