INSERT INTO public.opportunity VALUES (203, 'Nachhilfe in Deutsch, Englisch und Mathe für einen Schüler der 3. Klasse aus Georgien', 'volunteering', '30 Min etwa Unterricht. Demetre erlebe ich als ein lieber, ruhiger und neugieriger Junge. Mit der Mutter will er leider nicht lernen. Daher bat mich die Mutter um Unterstützung.', 'noTranslation', '', '2025-11-01 20:51:25.071145', '2025-11-01 20:51:25.071145', 739, 58);
INSERT INTO public.opportunity VALUES (204, 'Nachhilfe für einen Erwachsenen, der gerade seine Ausbildung begonnen hat.', 'volunteering', 'Die Zeit und der Wochentag, dan dem die Hilfe benötigt wird, stehen noch nicht fest.', 'noTranslation', '', '2025-11-01 20:51:25.087801', '2025-11-01 20:51:25.087801', 740, 61);
INSERT INTO public.opportunity VALUES (205, 'Sprachmittlung auf Farsi, Türkisch und/oder Kurdisch', 'volunteering', 'Wir benötigen Sprachmittler, die unsere Sozialarbeiterinnen in den Sprechstunden unterstützen können. Die Sprechstunden findet montags, dienstags, donnerstags und freitags von 10 bis 12Uhr und montags, dienstags und donnerstags von 14-16Uhr statt. Die Sprachen, die wir benötigen, sind  Farsi, Türkisch und/oder Kurdisch aber vor allem Persisch. Auch hier freuen wir für jede Zeit und jedes Datum, das möglich ist; wir würden diese Unterstützung sehr zu schätzen wissen. Vielen Dank im Voraus!', 'noTranslation', '', '2025-11-01 20:51:25.111731', '2025-11-01 20:51:25.111731', 741, 3);
INSERT INTO public.opportunity VALUES (206, 'Begleitung zur  Brustzentrum Charite', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:25.139328', '2025-11-01 20:51:25.139328', 742, 72);
INSERT INTO public.opportunity VALUES (207, 'Begleitung zur Nuclearmed', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:25.155294', '2025-11-01 20:51:25.155294', 743, 72);
INSERT INTO public.opportunity VALUES (208, 'Ehrenamtliche für KIEZTANDEMs gesucht!', 'volunteering', 'Das KIEZTANDEM bringt Menschen mit Flucht- und Migrationserfahrung und interessierte Freiwillige, die schon länger in Berlin leben, zusammen.  Je nach Interessen und Hobbys finden wir, das hauptamtliche Team, einen oder eine passende Tandempartner:in. Die freiwillig engagieren Nachbarinnen und Nachbarn unterstützen als Patinnen und Paten bei der Orientierung und Alltagsbewältigung der Zugewanderten im neuen Lebensumfeld, indem sie z. B. zusammen den Kiez erkunden, gemeinsam Freizeit verbringen, beim Erlernen der deutschen Sprache oder bei Behördengängen.  Die Tandems verbringen 2-3 Stunden Zeit pro Woche. Das hauptamtliche Team begleitet die Tandems und organisiert Austauschtreffen, Fortbildungen und Ausflüge für die Tandems und Interessierte.  Das Team ist außerdem zuständig für den Prozess des Matchings und die Begleitung der Patenschaften. Die Projektmitarbeiterinnen sind Ansprechpersonen für Fragen, Probleme, Idee u.a.  Voraussetzungen für ein Engagement im KIEZTANDEM: Sie müssen mindestens 18 Jahre alt sein; Interesse am interkulturellen Dialog haben; es sollte die Bereitschaft da sein, an Qualifizierungsseminaren teilzunehmen; Sie sollten Freude am Austausch und gemeinsamen Aktivitäten haben.  Ehrenamtliche Tandempartner:innen müssen keine ausgebildeten Fachkräfte oder Sozialarbeiter:innen sein.', 'noTranslation', '', '2025-11-01 20:51:25.184605', '2025-11-01 20:51:25.184605', 744, 73);
INSERT INTO public.opportunity VALUES (209, 'Begleitung zur Neurologie', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:25.201784', '2025-11-01 20:51:25.201784', 745, 5);
