INSERT INTO public.opportunity VALUES (222, 'Unterstützung für unser Männercafé', 'volunteering', 'Wir organisieren mit dem BENN-Team ein Männercafé für die Bewohner und planen ein Mal pro Monat auch Männer aus der Nachbarschaft einzuladen. Dafür brauchen wir einen Freiwilligen, der die Männer sprachlich unterstütz, indem er Deutsch-Farsi und Farsi-Deutsch übersetzt. Es gibt derzeit keinen festen Termin.', 'noTranslation', '', '2025-11-01 20:51:25.464508', '2025-11-01 20:51:25.464508', 758, 41);
