INSERT INTO public.opportunity VALUES (236, 'Nachhilfe', 'volunteering', 'Möchten Sie Kinder und Jugendliche beim Lernen unterstützen? Wir suchen Freiwillige, die regelmäßig bei den Hausaufgaben helfen und Freude am gemeinsam Lernen haben. In einer offenen und freundlichen Atmosphäre können Sie Wissen vermitteln, Motivation fördern un einen wertvollen Beitrag zur Bildung leisten. Die Kinder freuen sich schon auf Sie!', 'noTranslation', '', '2025-11-01 20:51:25.817604', '2025-11-01 20:51:25.817604', 772, 12);
