INSERT INTO public.opportunity VALUES (239, 'Nachhilfe Grundschule / Oberschule', 'volunteering', 'Wir bräuchten Unterstützung für unsere Schüler.', 'noTranslation', '', '2025-11-01 20:51:25.891628', '2025-11-01 20:51:25.891628', 775, 35);
INSERT INTO public.opportunity VALUES (240, 'Begleitung zu Augenarzt', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:25.908101', '2025-11-01 20:51:25.908101', 776, 18);
INSERT INTO public.opportunity VALUES (241, 'Deutschlernen A1.2', 'volunteering', 'In der Nachhilfe können gemeinsam die Unterlagen aus dem Kursbuch nachbearbeitet werden, Hausaufgaben erledigt werden, sich einfach so unterhalten werden oder die/der Ehrenamtliche nutzt Unterlagen aus unserem Fundus hier in der Unterkunft oder bringt- sehr gern auch- eigene Ideen ein.   Shoukreya kann sich gut Montags bis Donnerstag am Nachmittag ab 14.30 Uhr bis 18 Uhr flexibel treffen, gern ein- bis zweimal wöchentlich an einem regelmäßigen Tag. Es wäre am Einfachsten für Sie, wenn man sich im Hausaufgabenraum im Osteweg treffen könnte.', 'noTranslation', '', '2025-11-01 20:51:25.924835', '2025-11-01 20:51:25.924835', 777, 36);
INSERT INTO public.opportunity VALUES (242, 'Job Center Spandau Termin Begleitung', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:25.942996', '2025-11-01 20:51:25.942996', 778, 32);
INSERT INTO public.opportunity VALUES (243, 'Begleitung zum MVZ für Familien', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:25.964217', '2025-11-01 20:51:25.964217', 779, 78);
INSERT INTO public.opportunity VALUES (244, 'Übersetzungsbegleitung zur Sparkasse (Kontoeröffnung)', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:25.982998', '2025-11-01 20:51:25.982998', 780, 18);
