INSERT INTO public.opportunity VALUES (246, 'Unterstützung Mathe 8.Klasse', 'volunteering', 'Eine Schülerin (15 Jahre alt) sucht eine Frau, die mit ihr gemeinsam Mathe üben kann ( (zzt. Binomische Formeln).', 'noTranslation', '', '2025-11-01 20:51:26.021308', '2025-11-01 20:51:26.021308', 782, 36);
