INSERT INTO public.opportunity VALUES (249, 'Begleitung von Nachhilfe für Kinder und Jugendliche', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.089308', '2025-11-01 20:51:26.089308', 785, 79);
