INSERT INTO public.opportunity VALUES (251, 'Begleitung zu Kinder Physiotherapie', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.132668', '2025-11-01 20:51:26.132668', 787, 78);
INSERT INTO public.opportunity VALUES (252, 'Begleitung zu Kinder Physiotherapie', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.157935', '2025-11-01 20:51:26.157935', 788, 78);
INSERT INTO public.opportunity VALUES (253, 'Begleitung zu Kinder Physiotherapie', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.187939', '2025-11-01 20:51:26.187939', 789, 78);
INSERT INTO public.opportunity VALUES (254, 'Unterstütze in den Ferien mit den Kindern', 'volunteering', 'Habt ihr Lust vielleicht nächste Woche, mir, in den Ferien mit den Kindern zu helfen? Zum Beispiel Mittwoch (05.02) können wir vormittags ins Kino gehen da wäre eine Unterstützung cool und am Freitag (07.02) könnten wir mit den Kindern kochen/Pizza machen.', 'noTranslation', '', '2025-11-01 20:51:26.205592', '2025-11-01 20:51:26.205592', 790, 33);
INSERT INTO public.opportunity VALUES (255, 'Nachhilfe in Pankow', 'volunteering', 'Unterstütze Kinder, indem du ihnen Nachhilfeunterricht in verschiedenen Schulfächern gibst. Grundschüler benötigen die meiste Unterstützung.', 'noTranslation', '', '2025-11-01 20:51:26.222785', '2025-11-01 20:51:26.222785', 791, 40);
INSERT INTO public.opportunity VALUES (256, 'Nachhilfe für Kinder in Neukölln', 'volunteering', 'Es werden Freiwillige gesucht, die Schulkindern bei ihren Hausaufgaben helfen. Die Kinder sprechen Deutsch.', 'noTranslation', '', '2025-11-01 20:51:26.242703', '2025-11-01 20:51:26.242703', 792, 62);
INSERT INTO public.opportunity VALUES (257, 'Nachhilfe in Lichtenberg', 'volunteering', 'Die Kinder sprechen Deutsch, wir wissen nichts über ihr Alter. Sie würden Hilfe in verschiedenen Fächern benötigen.', 'noTranslation', '', '2025-11-01 20:51:26.267493', '2025-11-01 20:51:26.267493', 793, 3);
INSERT INTO public.opportunity VALUES (258, 'Begleitung zum Hautarzt', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.288507', '2025-11-01 20:51:26.288507', 794, 78);
INSERT INTO public.opportunity VALUES (259, 'Sprachmittlungsbegleitung zum Standesamt', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.30467', '2025-11-01 20:51:26.30467', 795, 18);
INSERT INTO public.opportunity VALUES (260, 'Dolmetscher (Arabisch-Deutsch) zum KJGD', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.325238', '2025-11-01 20:51:26.325238', 796, 18);
INSERT INTO public.opportunity VALUES (261, 'Begleitung zur Verbraucherzentrale', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.344356', '2025-11-01 20:51:26.344356', 797, 9);
INSERT INTO public.opportunity VALUES (262, 'Sporttrainer*in für einen Sportraum', 'volunteering', 'Für unseren kleinen Sportraum benötigen wir einen männlichen sowie eine weibliche Ehrenamtliche, die Lust und Spaß daran hätte unsere Bewohner Anleitungen zur Anwendung der Sportgeräte zu geben. Im Moment haben wir ein Fausthantelset, ein Liegestützgriff sowie Mini-Bänder. Yoga-Matten haben wir ebenfalls. Da Männer und Frauen getrennt trainieren möchten brauchen wir entsprechen 1 männlicher Ehrenamtliche für den Männern und 1 weibliche Ehrenamtliche für die Frauen.', 'noTranslation', '', '2025-11-01 20:51:26.370917', '2025-11-01 20:51:26.370917', 798, 60);
INSERT INTO public.opportunity VALUES (263, 'Vivantes MVZ Landsberger Allee Gesundheitszentrum für Kinder', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.388227', '2025-11-01 20:51:26.388227', 799, 7);
INSERT INTO public.opportunity VALUES (264, 'Ehrenamtliche*r für die Fahrradwerkstatt', 'volunteering', 'Die Gemeinschaftsunterkunft Kiefholzstraße 71 verfügt über eine vollständige Fahrradwerkstatt. Werkzeug ist vorhanden. Der oder die Freiwillige kann ein bis zwei Stunden in der Woche alte Fahrräder reparieren, welche Bewohnenden dann zu verfügung gestellt werden. Eine weitere Aufgabe ist es den Kindern der Unterkunft beim Aufpumpen der eigenen Fahrräder zu helfen oder Schrauben wieder fest zu drehen.', 'noTranslation', '', '2025-11-01 20:51:26.415976', '2025-11-01 20:51:26.415976', 800, 63);
INSERT INTO public.opportunity VALUES (265, 'Dolmetschung für Arzttermin', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.43441', '2025-11-01 20:51:26.43441', 801, 78);
INSERT INTO public.opportunity VALUES (266, 'Bastelstunden in Treptow', 'volunteering', 'Organisiere Aktivitäten für Kinder und unterstütze die Kinderbetreuer*innen bei der Planung von Bastelaktivitäten.', 'noTranslation', '', '2025-11-01 20:51:26.461124', '2025-11-01 20:51:26.461124', 802, 22);
INSERT INTO public.opportunity VALUES (267, 'Sprachmittlung Farsi-Deutsch für unseren Sozialdienst', 'volunteering', 'Wir suchen nach Unterstützung mit der Farsi-Deutsch-Sprachmittlung für unseren Sozialdienst während Sprechstunden. Ihr könnt uns entweder vor Ort oder telefonisch unterstützen, die Zeiten besprechen wir mit jeder*n persönlich.', 'noTranslation', '', '2025-11-01 20:51:26.483389', '2025-11-01 20:51:26.483389', 803, 36);
INSERT INTO public.opportunity VALUES (268, 'Nachhilfe ab 5. Klasse', 'volunteering', 'Wir suchen nach Freiwilligen, die die Kinder ab 5. Klasse Nachhilfe-Unterricht anbieten können.', 'noTranslation', '', '2025-11-01 20:51:26.502105', '2025-11-01 20:51:26.502105', 804, 36);
INSERT INTO public.opportunity VALUES (269, 'Sport für Geflüchtete', 'volunteering', 'Treibe Sport mit den Bewohner*innen unserer Unterkunft zusammmen!', 'noTranslation', '', '2025-11-01 20:51:26.533841', '2025-11-01 20:51:26.533841', 805, 7);
INSERT INTO public.opportunity VALUES (270, 'Basteln & Malangebote für Kinder', 'volunteering', 'Wir suchen nach Freiwillige, die mit den Kinder zusammen malen und basteln möchten.', 'noTranslation', '', '2025-11-01 20:51:26.559361', '2025-11-01 20:51:26.559361', 806, 7);
INSERT INTO public.opportunity VALUES (271, 'Biete Frauen eine Sportstunde an', 'volunteering', 'Wir suchen nach einer Trainerin, die den Frauen in unserer Unterkunft eine Sportstunde (z.B. Bewegungsübungen oder Ähnliches) anbieten könnte.', 'noTranslation', '', '2025-11-01 20:51:26.60063', '2025-11-01 20:51:26.60063', 807, 81);
INSERT INTO public.opportunity VALUES (272, 'Begleitung zur Klinik für Psychiatrie', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.615855', '2025-11-01 20:51:26.615855', 808, 1);
INSERT INTO public.opportunity VALUES (273, 'Begleitung zum Arzttermin', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.631316', '2025-11-01 20:51:26.631316', 809, 39);
INSERT INTO public.opportunity VALUES (274, 'Unterstütze ein Frauentreffen bei Handarbeit', 'volunteering', 'Wir organisieren freitags nachmittags ab 15.00 Uhr einen Frauentreff und könnte dafür auch Unterstützung gebrauchen. Beim Frauentreff werden Handarbeiten (Stricken, Nähen, Basteln etc.) angeboten.  Für die Zukunft sind auch Ausflüge geplant. Wichtig ist, dass es eine weibliche Freiwillige ist.', 'noTranslation', '', '2025-11-01 20:51:26.65494', '2025-11-01 20:51:26.65494', 810, 60);
INSERT INTO public.opportunity VALUES (275, 'Sprachcafé für Männer*', 'volunteering', 'Organisiere und leite ein Sprachcafé für Männer* in einer Gemeinschaftsunterkunft in Neukölln. Es wäre toll, wenn Du in diesem Bereich schon Erfahrung hättest und regelmäßig kommen könntest.', 'noTranslation', '', '2025-11-01 20:51:26.68149', '2025-11-01 20:51:26.68149', 811, 82);
INSERT INTO public.opportunity VALUES (276, 'Gestalte didaktische Aktivitäten für Kinder', 'volunteering', 'Wir suchen Freiwillige, die Lust haben, einmal in der Woche mit Kindern eine pädagogische Aktivität zu machen (Musik, Kunst, Basteln, Geschichten vorlesen und darüber sprechen, oder auch Gärtnern, Backen, Sport...). Wir sind offen für Ideen.  Uhrzeiten: Dienstag, Mittwoch oder Freitag ab 16.30 Uhr bis spätestens 18.00 Uhr.', 'noTranslation', '', '2025-11-01 20:51:26.705278', '2025-11-01 20:51:26.705278', 812, 60);
INSERT INTO public.opportunity VALUES (277, 'Dolmetscher (Arabisch-Deutsch)', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:26.717974', '2025-11-01 20:51:26.717974', 813, 18);
INSERT INTO public.opportunity VALUES (278, 'Begleitung/dolmetschen zum Arzttermin', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.736544', '2025-11-01 20:51:26.736544', 814, 78);
INSERT INTO public.opportunity VALUES (279, 'Kinderbetreuung in Wilmersdorf', 'volunteering', 'In der Regel sind es 3-7 Kinder und 1 Kinderbetreuerin. Sie wünschte sich Unterstützung und jemanden, der neue Ideen in die Kinderbetreuung bringt.
INSERT INTO public.opportunity VALUES (280, 'Nachhilfe für unsere Schulkinder', 'volunteering', 'Wir freuen uns über Freiwillige, die gerne mit Kindern arbeiten und ihnen bei den Hausaufgaben und bei der Vorbereitung von Prüfungen helfen.', 'noTranslation', '', '2025-11-01 20:51:26.775977', '2025-11-01 20:51:26.775977', 816, 2);
INSERT INTO public.opportunity VALUES (281, 'Begleitung zum Termin, Übersetzung Französisch', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.790507', '2025-11-01 20:51:26.790507', 817, 61);
INSERT INTO public.opportunity VALUES (282, 'Gartenarbeit in Neukölln', 'volunteering', 'Der Zeitplan ist flexibel und kann mit den Freiwilligen abgesprochen werden. Die Idee ist, neue Hochbeete zu bauen und sie mit allem zu bepflanzen, was die Bewohner*innen dort haben möchten.', 'noTranslation', '', '2025-11-01 20:51:26.80854', '2025-11-01 20:51:26.80854', 818, 60);
INSERT INTO public.opportunity VALUES (283, 'Dolmetscher Arabisch oder Kurmandschi', 'volunteering', '', 'deutsche', '', '2025-11-01 20:51:26.831458', '2025-11-01 20:51:26.831458', 819, 20);
INSERT INTO public.opportunity VALUES (284, 'Sei Teil der Fahrradwerkstatt', 'volunteering', 'Sei Teil unserer Fahrradwerkstatt und repariere Fahrräder mit den Bewohner*innen zusammen.', 'noTranslation', '', '2025-11-01 20:51:26.856489', '2025-11-01 20:51:26.856489', 820, 63);
INSERT INTO public.opportunity VALUES (285, 'Begleitung zum Virchow Klinikum (Charite)', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.874519', '2025-11-01 20:51:26.874519', 821, 83);
INSERT INTO public.opportunity VALUES (286, 'Begleitung zur Schuldnerberatung und Insolvenzberatung', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.889876', '2025-11-01 20:51:26.889876', 822, 9);
INSERT INTO public.opportunity VALUES (287, 'Begleitung zur Charite', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.904915', '2025-11-01 20:51:26.904915', 823, 54);
INSERT INTO public.opportunity VALUES (288, 'Unterstütze queere Geflüchtete bei Ankommen in Berlin', 'volunteering', 'Unterstütze queere Geflüchtete, die neu in Berlin sind, dabei, die Stadt und ihre Infrastruktur kennenzulernen!
INSERT INTO public.opportunity VALUES (289, 'Begleitung zur Augenklinik (Vivantes Neukölln)', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:26.952578', '2025-11-01 20:51:26.952578', 825, 78);
INSERT INTO public.opportunity VALUES (290, 'Winterfest in Lichtenberg', 'volunteering', 'Eine Unterkunft in Lichtenberg plant ein Winterfest für die Bewohner*innen. Freiwillige werden gesucht für
INSERT INTO public.opportunity VALUES (291, 'Unterstützung bei der Gartenarbeit (Gemüsegarten)', 'volunteering', 'Es gibt einen kleinen Gemüsegarten im Hof, und die Mitarbeiter*innen würden sich über die Unterstützung einer Person freuen, die sich mit dem Gärtnern auskennt.
INSERT INTO public.opportunity VALUES (292, 'Organisiere Sportunterricht für Jugendliche', 'volunteering', 'Organisiere sportliche Aktivitäten, z. B. Tischtennis, Tischfußball, Basketball, Kickboxen usw. für Jugendliche und Kinder in einer Unterkunft!
INSERT INTO public.opportunity VALUES (293, 'Begleite Kinder aus Grünau nach Altglienicke', 'volunteering', 'Begleite Kinder, die in einer Unterkunft in Grünau leben, einmal pro Woche zum Zirkus Cabuwazi in Altglienicke und zurück.', 'noTranslation', '', '2025-11-01 20:51:27.030295', '2025-11-01 20:51:27.030295', 829, 16);
INSERT INTO public.opportunity VALUES (294, 'Accompany to the Charité (Neurology)', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.047016', '2025-11-01 20:51:27.047016', 830, 39);
INSERT INTO public.opportunity VALUES (295, 'Accompany to the Charité (Neurology)', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.070229', '2025-11-01 20:51:27.070229', 831, 39);
INSERT INTO public.opportunity VALUES (296, 'Accompany to a debt counselling', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.085581', '2025-11-01 20:51:27.085581', 832, 9);
INSERT INTO public.opportunity VALUES (297, 'Begleitung zum Psychiatrietermin', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.104304', '2025-11-01 20:51:27.104304', 833, 64);
INSERT INTO public.opportunity VALUES (298, 'Aktivitäten für Kleinkinder (1-3 Jahre)', 'volunteering', 'Plane Aktivitäten für Kleinkinder (1-3 Jahre) in einer Gemeinschaftsunterkunft für Geflüchtete. Sie haben vor kurzem einen speziellen Raum für Kleinkinder eröffnet und würden gerne von Freiwilligen unterstützt werden, die Erfahrung mit kleinen Kindern haben und gerne Zeit mit ihnen verbringen.', 'noTranslation', '', '2025-11-01 20:51:27.118463', '2025-11-01 20:51:27.118463', 834, 61);
INSERT INTO public.opportunity VALUES (299, 'Brettspiele mit Jugendlichen spielen', 'volunteering', 'Spiele Brettspiele mit Jugendlichen im neuen Jugendraum in der Gemeinschaftsunterkunft für Geflüchtete. Dort gibt es auch einen Fernseher, damit du mit ihnen Filme anschauen kannst.', 'noTranslation', '', '2025-11-01 20:51:27.138516', '2025-11-01 20:51:27.138516', 835, 61);
INSERT INTO public.opportunity VALUES (300, 'Organisiere ein Sprachcafé in Britz', 'volunteering', 'Jeder*e Bewohner*in der Unterkunft ist willkommen, am Sprachcafé teilzunehmen. Das Ziel des Sprachcafés ist es, den Bewohnern einen sicheren Raum zu bieten, in dem sie Deutsch üben und nützliche Wörter und Redewendungen lernen können.
INSERT INTO public.opportunity VALUES (301, 'Supporting with daycare', 'volunteering', 'Die meisten der Kinder kommen aus Syrien. Die Koordinatorin der Tagesstätte spricht nur Deutsch. Sie brauchen eine unabhängige Person mit Erfahrung in der Kinderbetreuung.
INSERT INTO public.opportunity VALUES (302, 'Plane Ausflüge für Frauen in Britz', 'volunteering', 'Freiwillige können mit ihnen in Museen gehen, in der Nachbarschaft spazieren gehen oder andere schöne Dinge unternehmen. Museen und Galerien bieten manchmal kostenlose Eintrittskarten für Geflüchtete an.', 'noTranslation', '', '2025-11-01 20:51:27.213677', '2025-11-01 20:51:27.213677', 838, 82);
INSERT INTO public.opportunity VALUES (303, 'Accompany to an MRI appointment', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.228743', '2025-11-01 20:51:27.228743', 839, 40);
INSERT INTO public.opportunity VALUES (304, 'Nachhilfeunterricht (Englisch und Deutsch) in Zehlendorf', 'volunteering', 'Sie brauchen Freiwillige, die Kinder bei der Nachhilfe und bei den Hausaufgaben (verschiedene Schulfächer, einschließlich Englisch) unterstützen können. Die Kinder sprechen Deutsch und sind in verschiedenen Klassenstufen. Die Freiwilligen sollten Deutsch sprechen können, außer für die englische Nachhilfe.', 'noTranslation', '', '2025-11-01 20:51:27.249039', '2025-11-01 20:51:27.249039', 840, 58);
INSERT INTO public.opportunity VALUES (305, 'Begleitung zum Neurologen', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.270544', '2025-11-01 20:51:27.270544', 841, 28);
INSERT INTO public.opportunity VALUES (440, 'Translation at Amtsgericht Schöneberg on the 28th of March at 9:30', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:29.864798', '2025-11-01 20:51:29.864798', 976, 10);
INSERT INTO public.opportunity VALUES (306, 'Nachhilfe in Neukölln', 'volunteering', 'Es handelt sich um eine regelmäßige Freiwilligenarbeit (einmal pro Woche). Es wird Unterstützung für Schulkinder in verschiedenen Fächern benötigt. Die Kinder sprechen Deutsch, also sollte der Freiwillige auch Deutsch sprechen können.', 'noTranslation', '', '2025-11-01 20:51:27.286424', '2025-11-01 20:51:27.286424', 842, 60);
INSERT INTO public.opportunity VALUES (307, 'Translate at the LAF', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.299998', '2025-11-01 20:51:27.299998', 843, 83);
INSERT INTO public.opportunity VALUES (308, 'Begleitung zur Hochschulambulanz für Augenheilkunde', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.320338', '2025-11-01 20:51:27.320338', 844, 10);
INSERT INTO public.opportunity VALUES (309, 'Unterstützung einer älteren Frau im Alltag', 'volunteering', 'Helfen Sie einer 80-jährigen Frau aus der Ukraine bei alltäglichen Verrichtungen, wie z. B. beim Einkaufen im Supermarkt, beim Schuhekaufen usw. Diese Möglichkeit ist flexibel und wird direkt mit dem Flüchtling vereinbart.', 'noTranslation', '', '2025-11-01 20:51:27.338158', '2025-11-01 20:51:27.338158', 845, 80);
INSERT INTO public.opportunity VALUES (310, 'Accompany a refugee to the appointment and back', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.353614', '2025-11-01 20:51:27.353614', 846, 58);
INSERT INTO public.opportunity VALUES (311, 'Accompany to a kid’s doctor', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.368579', '2025-11-01 20:51:27.368579', 847, 79);
INSERT INTO public.opportunity VALUES (312, 'Winterfest in Marzahn', 'volunteering', 'Für die Weihnachtsfeier am 13. Dezember können Sie den Kindern Weihnachtsgeschichten vorlesen und/oder den Weihnachtsmann spielen - ideal wären natürlich Weihnachtsgeschichten. Wenn Sie daran Spaß haben und kreativ sind, lassen Sie es uns wissen!', 'noTranslation', '', '2025-11-01 20:51:27.380568', '2025-11-01 20:51:27.380568', 848, 10);
INSERT INTO public.opportunity VALUES (313, 'Accompany to debt counselling', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.395507', '2025-11-01 20:51:27.395507', 849, 9);
INSERT INTO public.opportunity VALUES (314, 'Accompany to a counselling appointment', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.409562', '2025-11-01 20:51:27.409562', 850, 61);
INSERT INTO public.opportunity VALUES (315, 'Accompany to a pre-school check up', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.424188', '2025-11-01 20:51:27.424188', 851, 18);
INSERT INTO public.opportunity VALUES (316, 'Accompany to an MRI appointment', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.441404', '2025-11-01 20:51:27.441404', 852, 78);
INSERT INTO public.opportunity VALUES (317, 'Begleitung zum Unfallkrankenhaus Berlin', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.462538', '2025-11-01 20:51:27.462538', 853, 10);
INSERT INTO public.opportunity VALUES (318, 'Support with daycare in Lichtenberg', 'volunteering', 'Sie brauchen Freiwillige, die sie bei der Kinderbetreuung unterstützen und neue kreative Ideen einbringen.', 'noTranslation', '', '2025-11-01 20:51:27.487855', '2025-11-01 20:51:27.487855', 854, 3);
INSERT INTO public.opportunity VALUES (319, 'Begleitung zur Charité', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.50202', '2025-11-01 20:51:27.50202', 855, 8);
INSERT INTO public.opportunity VALUES (320, 'Sprachmittlung für Sozialarbeiter*innen', 'volunteering', 'Sie brauchen Freiwillige, die die Sozialarbeiter*innen bei den Beratungen für die Bewohner*innen unterstützen. Der Zeitplan wird individuell besprochen.', 'noTranslation', '', '2025-11-01 20:51:27.520929', '2025-11-01 20:51:27.520929', 856, 3);
