INSERT INTO public.opportunity VALUES (322, 'Begleitung zur Charité Wedding', 'volunteering', 'Klinik für Hepatopogie und Gastoenterologie, Sprechstunde für gastrointestinale Onkologie', 'noTranslation', '', '2025-11-01 20:51:27.553619', '2025-11-01 20:51:27.553619', 858, 46);
