INSERT INTO public.opportunity VALUES (325, 'Accompany to the Charit', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.599551', '2025-11-01 20:51:27.599551', 861, 10);
INSERT INTO public.opportunity VALUES (326, 'Translate from English to German for a doctor’s appointment', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.621788', '2025-11-01 20:51:27.621788', 862, 84);
INSERT INTO public.opportunity VALUES (327, 'Begleitung zum Arzttermin (Gastroenterologie)', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.638421', '2025-11-01 20:51:27.638421', 863, 40);
