INSERT INTO public.opportunity VALUES (330, 'Begleitung zur Schulanmeldung', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.694975', '2025-11-01 20:51:27.694975', 866, 77);
INSERT INTO public.opportunity VALUES (331, 'Begleitung zu einer MRT-Untersuchung', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.710822', '2025-11-01 20:51:27.710822', 867, 40);
