INSERT INTO public.opportunity VALUES (335, 'Begleitung zur Physiotherapie', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.779229', '2025-11-01 20:51:27.779229', 871, 46);
INSERT INTO public.opportunity VALUES (336, 'Accompany to a paediatrician appointment', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.793016', '2025-11-01 20:51:27.793016', 872, 79);
INSERT INTO public.opportunity VALUES (337, 'Accompany to a pediatrician appointment', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.807127', '2025-11-01 20:51:27.807127', 873, 39);
INSERT INTO public.opportunity VALUES (338, 'Accompany to a radiology appointment', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.822214', '2025-11-01 20:51:27.822214', 874, 79);
INSERT INTO public.opportunity VALUES (339, 'Accompany to an apartment viewing', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.838359', '2025-11-01 20:51:27.838359', 875, 83);
INSERT INTO public.opportunity VALUES (340, 'Sprachmittlung für eine Schulhilfekonferenz', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.85411', '2025-11-01 20:51:27.85411', 876, 64);
INSERT INTO public.opportunity VALUES (341, 'Accompany to a neurology appointment', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.871107', '2025-11-01 20:51:27.871107', 877, 79);
INSERT INTO public.opportunity VALUES (342, 'Begleitung zur Physiotherapie', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:27.887174', '2025-11-01 20:51:27.887174', 878, 46);
INSERT INTO public.opportunity VALUES (343, 'Sprachcafé in Neukölln', 'volunteering', 'Dieses Sprachcafé gibt es nun schon seit über einem Jahr. Es hat eine Kerngruppe von Teilnehmer*innen, die hauptsächlich Arabisch sprechen, aber alle sind willkommen, sich ihm anzuschließen.', 'noTranslation', '', '2025-11-01 20:51:27.902803', '2025-11-01 20:51:27.902803', 879, 39);
INSERT INTO public.opportunity VALUES (344, 'Spiele Brettspiele mit Bewohner*innen einer Unterkunft in Grünau', 'volunteering', 'Spielen Sie Tischspiele mit den Bewohnern!', 'noTranslation', '', '2025-11-01 20:51:27.932812', '2025-11-01 20:51:27.932812', 880, 85);
INSERT INTO public.opportunity VALUES (345, 'Nachhilfeunterricht in Grünau', 'volunteering', 'Unterstütze die Kinder beim Erlernen und Verbessern ihrer Deutschkenntnisse und beim Erledigen ihrer Hausaufgaben.', 'noTranslation', '', '2025-11-01 20:51:27.962886', '2025-11-01 20:51:27.962886', 881, 85);
INSERT INTO public.opportunity VALUES (346, 'Deutschunterricht in Grünau', 'volunteering', 'Unterstütze die Bewohner*innen beim Erlernen und Verbessern ihrer Deutschkenntnisse:
INSERT INTO public.opportunity VALUES (347, 'Englisch- und Deutschnachhilfe für eine arabischsprachige Person', 'volunteering', 'Eine Geflüchtete studiert Sozialarbeit und braucht Unterstützung in Deutsch und Englisch.', 'noTranslation', '', '2025-11-01 20:51:28.008149', '2025-11-01 20:51:28.008149', 883, 64);
INSERT INTO public.opportunity VALUES (348, 'Tischtennis spielen in Treptow-Köpenick', 'volunteering', 'Im Hof gibt es eine Tischtennisplatte. Sie brauchen einen Freiwilligen, der vorbeikommt und mit den Bewohnern spielt. Die Zeiten können flexibel sein.', 'noTranslation', '', '2025-11-01 20:51:28.033008', '2025-11-01 20:51:28.033008', 884, 85);
INSERT INTO public.opportunity VALUES (349, 'Unterstützung bei der Einrichtung eines Raums für Jugendliche in Lichtenberg', 'volunteering', 'Sie sind gerade dabei, ihren Jugendraum zu gestalten und suchen derzeit eine freiwillige Person, die ihnen bei der Gestaltung des Raums hilft und den Raum dann 1-2 Mal pro Woche nachmittags für Kinder zwischen 9 und 17 Jahren betreut.', 'noTranslation', '', '2025-11-01 20:51:28.058412', '2025-11-01 20:51:28.058412', 885, 4);
INSERT INTO public.opportunity VALUES (350, 'Sportstunde für Erwachsene', 'volunteering', 'Organisiere sportliche Aktivitäten für Erwachsene!', 'noTranslation', '', '2025-11-01 20:51:28.074031', '2025-11-01 20:51:28.074031', 886, 57);
INSERT INTO public.opportunity VALUES (351, 'Accompany groups of children to a swimming class', 'volunteering', 'Volunteers are needed to accompany groups of children to a swimming class during the autumn break.', 'noTranslation', '', '2025-11-01 20:51:28.090586', '2025-11-01 20:51:28.090586', 887, 20);
INSERT INTO public.opportunity VALUES (352, 'Begleite Kinder zum Judo-Unterricht', 'volunteering', 'In der Unterkunft gibt es Kinder, die sich für das Judotraining interessieren.
INSERT INTO public.opportunity VALUES (353, 'Büchervorlesung für Kinder in Karow', 'volunteering', 'Unterstütze die Kinderbetreuer*innen, indem du Bücher für oder mit Kindern in der Unterkunft liest.', 'noTranslation', '', '2025-11-01 20:51:28.124992', '2025-11-01 20:51:28.124992', 889, 86);
INSERT INTO public.opportunity VALUES (354, 'Sprachcafé/Deutschunterricht in Karow', 'volunteering', 'Es werden Freiwillige gesucht, die den Bewohnern die Grundlagen der deutschen Sprache beibringen (erste Begriffe des täglichen Lebens etc.) oder Nachhilfe geben. Ein bis zweimal pro Woche wäre ausreichend.
INSERT INTO public.opportunity VALUES (355, 'Englischunterricht für einen Jugendlichen', 'volunteering', 'Ein 14-jähriger Junge sucht Unterstützung in Englisch, da er Schwierigkeiten hat, mit dem Lehrplan seiner Englischklasse Schritt zu halten.
INSERT INTO public.opportunity VALUES (356, 'Unterstütze eine Klederkammer in Karow', 'volunteering', 'Derzeit wird Hilfe für die Kleiderkammer benötigt. Dies betrifft sowohl das Einsortieren der Kleidung in die Regale nach Art und Größe als auch die Verteilung der Kleidung, wenn eine Person oder Familie aus dem Zentrum etwas benötigt. Eine Unterstützung an nur einem Tag in der Woche wäre sehr hilfreich.', 'noTranslation', '', '2025-11-01 20:51:28.171434', '2025-11-01 20:51:28.171434', 892, 86);
INSERT INTO public.opportunity VALUES (357, 'Einmal pro Woche für Sozialarbeiter*innen übersetzen', 'volunteering', 'Die Sozialarbeiterinnen einer Unterkunft in Pankow brauchen Unterstützung beim Übersetzen ins Französische und Deutsche für neue Bewohnerinnen. Der Zeitplan ist flexibel und sollte nicht mehr als 2-3 Stunden pro Tag einmal pro Woche oder weniger in Anspruch nehmen, wenn du nicht jede Woche verfügbar bist.
INSERT INTO public.opportunity VALUES (358, 'Unterstütze Sozialarbeiter*innen durch Sprachmittlung', 'volunteering', 'Wöchentliche Unterstützung für Sozialarbeiter - die Zeiten hängen von den Freiwilligen ab.
INSERT INTO public.opportunity VALUES (359, 'Organisiere Kinderbetreuung in Lichtenberg', 'volunteering', 'Sie brauchen Freiwillige, die helfen, Aktivitäten für Kinder zu organisieren und die Betreuer*innen zu unterstützen. Die Zeiten können mit dem Freiwilligen abgesprochen werden. Die meisten Kinder gehen zur Schule, daher findet die meiste Zeit der Tagesbetreuung zwischen 14 und 17 Uhr statt.', 'noTranslation', '', '2025-11-01 20:51:28.25004', '2025-11-01 20:51:28.25004', 895, 4);
INSERT INTO public.opportunity VALUES (360, 'Sprachcafé in Hellersdorf', 'volunteering', 'Die Bewohner*innen einer Unterkunft wollen ihr Deutsch verbessern und können auch anderen Menschen ihre Sprache beibringen. Wenn jemand z.B. Farsi lernen möchte, kann er mit einem Bewohner ein Sprachtandem machen und sich gegenseitig helfen.
INSERT INTO public.opportunity VALUES (361, 'Unterstütze bei der Hausaufgabenhilfe', 'volunteering', 'Hausaufgabenhilfe für alle Altersstufen.', 'noTranslation', '', '2025-11-01 20:51:28.282793', '2025-11-01 20:51:28.282793', 897, 10);
INSERT INTO public.opportunity VALUES (362, 'Accompany to a neurology appointment', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:28.295438', '2025-11-01 20:51:28.295438', 898, 61);
INSERT INTO public.opportunity VALUES (363, 'Kinderbetreuung in Spandau', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:28.315693', '2025-11-01 20:51:28.315693', 899, 81);
INSERT INTO public.opportunity VALUES (364, 'Sommerfest Refugium Lichtenberg', 'volunteering', 'Auf-Abbau, Kinderschminken, Getränke/Snacks Ausgabe, Spielangebote, Hüpfburg Betreuung', 'noTranslation', '', '2025-11-01 20:51:28.333559', '2025-11-01 20:51:28.333559', 900, 4);
INSERT INTO public.opportunity VALUES (365, 'Richte eine Kleiderkammer ein', 'volunteering', 'Die Ehrenamtskoordinatorin möchte in der Unterkunft eine Kleiderkammer einrichten.
INSERT INTO public.opportunity VALUES (366, 'Mach Zuckerwatte bei einem Sommerfest', 'volunteering', 'Unterstützung bei der Herstellung von Zuckerwatte bei einem Sommerfest in einer Flüchtlingsunterkunft. Wenn Du ein paar Stunden Zeit hast, lass es uns bitte wissen!', 'noTranslation', '', '2025-11-01 20:51:28.370702', '2025-11-01 20:51:28.370702', 902, 1);
INSERT INTO public.opportunity VALUES (367, 'Unterstütze die Kleiderkammer in Hellersdorf', 'volunteering', 'Es gibt eine Kleiderkammer, in der zwei der Bewohner*innen ehrenamtlich tätig sind. Sie würden gerne von anderen Freiwilligen unterstützt werden.
INSERT INTO public.opportunity VALUES (368, 'Sprachcafé/Nachhilfe in Hellersdorf', 'volunteering', 'Einige der Bewohner*innen der Unterkunft besuchen bereits einen Deutschkurs und benötigen Unterstützung bei den Hausaufgaben, der Grammatik usw. Der Zeitplan ist flexibel und kann je nach Ihrer Verfügbarkeit geändert werden.
INSERT INTO public.opportunity VALUES (369, 'Unterstütze eine Kleiderkammer in Pankow', 'volunteering', 'Sie brauchen neue Freiwillige. Der Zeitplan kann mit der Ehrenamtskoordinatorin besprochen werden.', 'noTranslation', '', '2025-11-01 20:51:28.434618', '2025-11-01 20:51:28.434618', 905, 83);
INSERT INTO public.opportunity VALUES (370, 'Unterstütze mit Kinderbetreuung in Tempelhof', 'volunteering', 'Unterstütze die Kinderbetreuer*innen bei der Organisation von Spielen und Aktivitäten für die Kinder.
INSERT INTO public.opportunity VALUES (371, 'Männer*café  in Neukölln', 'volunteering', 'Das Männercafé bietet die Möglichkeit, von anderen Männern zu lernen und sich gegenseitig zu unterstützen. Workshops, Diskussionsgruppen und gemeinsame Aktivitäten werden angeboten, um Austausch und Wachstum zu fördern. Es ist ein Ort, an dem Männer* neue Perspektiven gewinnen können.
INSERT INTO public.opportunity VALUES (372, 'Kleiderkammer in Lichtenberg', 'volunteering', 'Die Kleiderkammer braucht Hilfe und jemanden, der sich engagieren möchte. Im Moment gibt es nur einen Freiwilligen, der sie unterstützt. Die Kleiderkammer ist mittwochs von 11:00 bis 13:00 Uhr geöffnet und die Freiwilligen können gerne zwei Stunden oder länger bleiben.', 'noTranslation', '', '2025-11-01 20:51:28.495744', '2025-11-01 20:51:28.495744', 908, 4);
INSERT INTO public.opportunity VALUES (373, 'Sommerfest in Lichtenberg', 'volunteering', 'Am 24.09. findet in einer Gemeinschaftsunterkunft ein Sommerfest statt. Dafür werden an diesem Tag von 14:00-18:00 Uhr helfende Hände gesucht für z.B: Auf- und Abbau von Tischen/Stühlen, Kinderschminken, Hüpfburg, Ausschank von Getränken und Popcorn, Tombola, etc.', 'noTranslation', '', '2025-11-01 20:51:28.516947', '2025-11-01 20:51:28.516947', 909, 4);
INSERT INTO public.opportunity VALUES (374, 'Deutschlernen für einen Geflüchteten aus Ukraine', 'volunteering', 'Es handelt sich um einen älteren ukrainischen Mann, der etwas Deutschkenntnisse benötigt. Er ist bis September zeitlich flexibel und bereit, sich mit dem Freiwilligen außerhalb der Unterkunft zu treffen. Es wäre am besten, wenn der Freiwillige auch älter ist.', 'noTranslation', '', '2025-11-01 20:51:28.532181', '2025-11-01 20:51:28.532181', 910, 80);
INSERT INTO public.opportunity VALUES (375, 'Sportfest Marzahn', 'volunteering', 'Das sind die Veranstaltungen, und jede Station braucht eine oder zwei Personen, die die Karten stempeln (die Teilnehmer könnten ihre Karten stempeln lassen und am Ende einen Preis für ihre Teilnahme bekommen) oder die Namen der Kinder aufschreiben, die teilnehmen möchten, oder die Kinder zu den richtigen Stationen führen, kurz gesagt, am Stand anwesend sein.', 'noTranslation', '', '2025-11-01 20:51:28.547717', '2025-11-01 20:51:28.547717', 911, 20);
INSERT INTO public.opportunity VALUES (376, 'Unterstütze beim Frauencafé', 'volunteering', 'Hast du gerade eine Person(gerne eine Frau),die Lust hast bei Frauencafé mitzuhelfen? Sowohl Unterstützung bei der Vorbereitung, Durchführung und Nachbereitung. Sie kann gerne ihre Idee einbringen. Eine plus wäre,wenn die Person türkisch, russisch, georgisch oder arabisch zusätzlich kann. Aber das ist kein Muss', 'noTranslation', '', '2025-11-01 20:51:28.571225', '2025-11-01 20:51:28.571225', 912, 4);
INSERT INTO public.opportunity VALUES (377, 'Unterstütze bei einem Sommerfest in Zehlendorf', 'volunteering', 'Freiwillige werden für die Organisation von Aktivitäten für Kinder, die Ausgabe von Speisen und Getränken, die Mithilfe beim Aufräumen usw. benötigt.', 'noTranslation', '', '2025-11-01 20:51:28.587882', '2025-11-01 20:51:28.587882', 913, 58);
INSERT INTO public.opportunity VALUES (378, 'Begleite Bewohner*innen zu einem FreiluftKino in Prenzlauerberg', 'volunteering', 'Könnte ich über euch Ehrenamtlichen finden, die Lust hätten einige Bewohner aus der Unterkunft abzuholen und mit denen zur Filmveranstaltung zu kommen? (20 min. zu fuß) Die Veranstaltung ist kostenlos, die Ehrenamtlichen + Bewohner bekommen die Getränke umsonst  
INSERT INTO public.opportunity VALUES (379, 'Unterstütze die Bewohner*innen, die Nachbarschaft in Wilmersdorf besser kennenzulernen', 'volunteering', 'Die Idee für diese Freiwilligenarbeit ist es, die Bewohner des RAC dabei zu unterstützen, neue Dinge in ihrer Nachbarschaft zu entdecken und zu unternehmen. Das könnte einmal im Monat oder alle zwei Wochen geschehen. Wenn es Gemeinschaftszentren, Sportspiele oder andere Aktivitäten für Kinder/Erwachsene gibt, wäre es die Aufgabe der Freiwilligen, die Bewohner*innen zu begleiten, damit sie sich akzeptiert und sicher fühlen.', 'noTranslation', '', '2025-11-01 20:51:28.638365', '2025-11-01 20:51:28.638365', 915, 56);
INSERT INTO public.opportunity VALUES (380, 'Suche nach Aktivitäten für Kinder in Wilmersdorf', 'volunteering', 'Es handelt sich um zwei Schwestern mit mehreren Kindern. Beide sind alleinerziehende Mütter, einige der Kinder sind behindert. Sie haben nicht die Zeit, sich um Aktivitäten und Unternehmungen für jedes Kind zu kümmern, deshalb wären sie froh, wenn sie dabei etwas Unterstützung bekämen.', 'noTranslation', '', '2025-11-01 20:51:28.65745', '2025-11-01 20:51:28.65745', 916, 56);
INSERT INTO public.opportunity VALUES (381, 'Play with kids and organise activities for the during a summer festival in Wilmersdorf', 'volunteering', 'Es werden Freiwillige gesucht, die Aktivitäten für Kinder organisieren können (Schminken, Spiele, Sport, Popcorn usw.).
INSERT INTO public.opportunity VALUES (382, 'Support with accompanying kids around in the neighborhood in Zehlendorf', 'volunteering', 'Begleiten Sie die Kinder zu verschiedenen Aktivitäten in der Nachbarschaft, z. B. Fußball usw.', 'noTranslation', '', '2025-11-01 20:51:28.690214', '2025-11-01 20:51:28.690214', 918, 58);
INSERT INTO public.opportunity VALUES (383, 'Unterstützung einer arabischsprachigen Familie bei dem Ankommen in Moabit', 'volunteering', 'Es handelt sich um eine große Familie, bestehend aus 7 Personen, die im April 2024 nach Berlin gezogen sind. Sie brauchen Hilfe, um sich in der Stadt zurechtzufinden, um etwas zu unternehmen usw. Die Großmutter der Familie ist behindert und benutzt einen Rollstuhl.', 'noTranslation', '', '2025-11-01 20:51:28.711826', '2025-11-01 20:51:28.711826', 919, 8);
INSERT INTO public.opportunity VALUES (384, 'Deutsch lernen und üben', 'volunteering', 'Sie kümmert sich um ihren Mann und hat sehr wenig Zeit, um Deutsch zu lernen. Es wäre toll, jemanden für ein Deutsch-Russisch/Deutsch-Ukrainisch zu haben.', 'noTranslation', '', '2025-11-01 20:51:28.733865', '2025-11-01 20:51:28.733865', 920, 8);
INSERT INTO public.opportunity VALUES (385, 'Sortierung  und Ausgabe von den Spenden der Tafel e.V.', 'volunteering', 'Wir suchen noch Leute, die uns bei der  Sortierung  und Ausgabe von den Spenden der Tafel e. V. am Montag und/oder  Freitag  zwischen 14 und 17 Uhr helfen.
INSERT INTO public.opportunity VALUES (386, 'Wegbegleitung für Kinder', 'volunteering', 'Gleich schon beginnen die Sommerferien. Damit unsere lieben Kinder sich aber nicht langweilen müssen, haben wir ihnen ein buntes Programm mit zahlreichen Aktivitäten und Ausflügen zusammengestellt.
INSERT INTO public.opportunity VALUES (387, 'Kinderbetreuung während Sommerpause', 'volunteering', 'Bis Ende August 
INSERT INTO public.opportunity VALUES (388, 'Unterstützung bei einem Sommerfest', 'volunteering', 'Es wäre großartig, wenn wir Freiwillige hätten, etwa für die folgenden Aktivitäten:
INSERT INTO public.opportunity VALUES (389, 'Fahrradwerkstatt in Zehlendorf', 'volunteering', 'Freiwillige fpr die Mitarbeit in der Fahrradselbsthilfewerkstatt (Tatsächlich auch als Honorarkraft auf selbstständiger Basis möglich)', 'noTranslation', '', '2025-11-01 20:51:28.834801', '2025-11-01 20:51:28.834801', 925, 58);
INSERT INTO public.opportunity VALUES (390, 'Kinderschminken für ein Sommerfest', 'volunteering', 'Wir suchen also vor allem nach Menschen, die Lust darauf haben, etwas mit Kindern zu machen oder mit Eltern und Kindern. Ganz konkret suchen wir aktuell nach einer Person, die bei unserem Sommerfest am 12.07. Kinderschminken anbietet.', 'noTranslation', '', '2025-11-01 20:51:28.84986', '2025-11-01 20:51:28.84986', 926, 54);
INSERT INTO public.opportunity VALUES (391, 'Unterstütze ein Männer*cafe in Pankow', 'volunteering', 'Es werden Freiwillige für ein Männer-Café gesucht (zwei Stunden, in denen sich die n Männer treffen und über Dinge reden können, die sie interessieren)', 'noTranslation', '', '2025-11-01 20:51:28.874664', '2025-11-01 20:51:28.874664', 927, 83);
INSERT INTO public.opportunity VALUES (392, 'Aktivitäten für Jugendliche in Pankow', 'volunteering', 'Es werden Freiwillige für einen sogenannten Jungstreff gesucht, bei dem sich Jugendliche treffen und gemeinsam etwas unternehmen.', 'noTranslation', '', '2025-11-01 20:51:28.899109', '2025-11-01 20:51:28.899109', 928, 83);
INSERT INTO public.opportunity VALUES (393, 'Gruppe von Freiwilligen für den Hangars', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:28.92086', '2025-11-01 20:51:28.92086', 929, 24);
INSERT INTO public.opportunity VALUES (394, 'Unterstütze mit Kinderbetreuung', 'volunteering', 'Wir benötigen grundsätzlich Unterstützung Mo, Mi und Do jeweils im Zeitraum 15:00 -18:00 Uhr.Mittwoch und Donnerstag jeweils als Unterstützung unserer eigenen Kinderbetreuung.', 'noTranslation', '', '2025-11-01 20:51:28.951171', '2025-11-01 20:51:28.951171', 930, 2);
INSERT INTO public.opportunity VALUES (395, 'Accompanying a family from Afghanistan to doctor’s appointments around Berlin', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:28.972891', '2025-11-01 20:51:28.972891', 931, 64);
INSERT INTO public.opportunity VALUES (396, 'Kinderbetreuung am Wochenende in Pankow', 'volunteering', '', 'noTranslation', '', '2025-11-01 20:51:28.991339', '2025-11-01 20:51:28.991339', 932, 83);
INSERT INTO public.opportunity VALUES (397, 'Einem Ehepaar aus Afghanistan in Moabit das Lesen und Schreiben auf Deutsch beibringen', 'volunteering', 'Sie sind älter und müssen Deutsch lesen und schreiben lernen, bevor sie einen Deutschkurs besuchen können.', 'noTranslation', '', '2025-11-01 20:51:29.011345', '2025-11-01 20:51:29.011345', 933, 8);
INSERT INTO public.opportunity VALUES (398, 'Aktivitäten für Frauen in Neukölln', 'volunteering', 'Es wird eine Freiwillige (Frau) gesucht, der unterhaltsame Aktivitäten für die Frauen im RAC organisiert. Das kann ein Ausflug sein oder etwas, das die Bewohner*innen interessiert.', 'noTranslation', '', '2025-11-01 20:51:29.034077', '2025-11-01 20:51:29.034077', 934, 62);
INSERT INTO public.opportunity VALUES (399, 'Organisieren Sie Kunst- und Bastelkurse für Kinder und Jugendliche in Neukölln', 'volunteering', 'Es werden Freiwillige für die Organisation von Kunst- und Handwerksaktivitäten für Kinder benötigt, z. B. Zeichnen, Malen, Formen, Origami usw.', 'noTranslation', '', '2025-11-01 20:51:29.058913', '2025-11-01 20:51:29.058913', 935, 62);
INSERT INTO public.opportunity VALUES (400, 'Führe ein Sprachcafé in Wedding', 'volunteering', 'Sie brauchen Freiwillige für Schlasch, ein Projekt des Club DIalog. Dort gibt es einmal pro Woche ein deutsches Sprachcafé für russisch- und ukrainischsprachige Jugendliche, in dem sie auf spielerische Weise ihr Deutsch üben können.', 'noTranslation', '', '2025-11-01 20:51:29.073783', '2025-11-01 20:51:29.073783', 936, 64);
INSERT INTO public.opportunity VALUES (401, 'Unterstütze ein Sprachcafé für Frauen in Hellersdorf', 'volunteering', 'Es gibt eine Gruppe von Frauen, die gerne jemanden hätten, mit dem sie ihr Deutsch üben können.
INSERT INTO public.opportunity VALUES (402, 'Organisiere Aktivitäten für die Kinderbetreuung in Lichtenberg', 'volunteering', 'Außer donnerstags gibt es keine Tagesbetreuung. Es gibt eine Kinderbetreuering, die Unterstützung braucht, da es ziemlich viele Kinder gibt.', 'noTranslation', '', '2025-11-01 20:51:29.118062', '2025-11-01 20:51:29.118062', 938, 87);
INSERT INTO public.opportunity VALUES (403, 'Kunst und Handwerk für Kinder und ihre Familien in Tempelhof', 'volunteering', 'Es ist bereits eine Freiwillige aktiv, die Unterstützung braucht. Kunst und Handwerk können unterschiedlich sein, je nachdem, was der Freiwillige kann (Zeichnen, Gießen, Bildhauerei usw.)', 'noTranslation', '', '2025-11-01 20:51:29.137388', '2025-11-01 20:51:29.137388', 939, 61);
INSERT INTO public.opportunity VALUES (404, 'Organisiere Aktivitäten für Kinder und Jugendliche in Marzahn - IB', 'volunteering', 'Alles, was Freiwillige als eigene Aktivitäten machen können. vorzugsweise mit Kindern und Jugendlichen ist vor allem bis 18.00 Uhr willkommen, aber nach einiger Eingewöhnung auch nach Feierabend. Zusätzlich manchmal Begleitung zur LEA oder zum Gericht', 'noTranslation', '', '2025-11-01 20:51:29.162084', '2025-11-01 20:51:29.162084', 940, 64);
INSERT INTO public.opportunity VALUES (405, 'Begleiten Sie Kinder beim KinderKulturMonat im Oktober in Berlin', 'volunteering', 'Der Kinder·Kultur·Monat ist ein Festival für Kinder und Ihre Familien in Berlin.
INSERT INTO public.opportunity VALUES (406, 'Nähen oder Stricken mit Frauen in Treptow-Köpenick', 'volunteering', 'Im Unterkunftszentrum gibt es Nähmaschinen und Materialien zum Stricken. Es wird eine Freiwillige gesucht, die zweimal im Monat mit den Frauen stricken/nähen könnte.', 'noTranslation', '', '2025-11-01 20:51:29.220934', '2025-11-01 20:51:29.220934', 942, 28);
INSERT INTO public.opportunity VALUES (407, 'Unterstütze ein türkischsprachiges Kind beim Deutschlernen in Treptow-Köpenick', 'volunteering', 'Kein Türkisch ist in Ordnung, die Freiwilligen müssen die beiden Treffen mit dem Kind in Anwesenheit des VC und der Mutter des Kindes abhalten (Dienstag/Mittwoch/Donnerstag).
