INSERT INTO public.volunteer VALUES (20, '', '- Shawky 13.06.24: Thanks a lot for filling out the volunteer information and preferences form. At the moment, we do not have any opportunities that could be done remotely, except for translations that involve knowledge of Arabic, Farsi, Turkish, Russian or Ukrainian. If something changes in the future and knowledge of Hindi, Kannada or Tamil is needed, we will definitely let you know. If something changes in your situation in the meantime and you are able to volunteer directly at one of the refugee accommodation centers we are working with, you could find a full list of the volunteer opportunities currently available on our website, etc.. / I’m interested in remote volunteering with very good English Skills and A2 German skills.I also know a lot of Indian languages.  -Vostel', 'Inactive', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'no', '2025-11-01 20:51:14.918024', '2025-11-01 20:51:14.918024', 21, 165);
