INSERT INTO public.volunteer VALUES (325, '', '12.03.25: Lives on the Gleisdreieck since a few months, and will be here for at least 1 year. He is passionate about history and politics, worked for 2 ministers with the Green Party in Belgium. He’s been a tutor for law and language (English and French), has a law background. Did a lot of gym fitness. Prefers works with adults or teenagers. Very basic German, he’s a part-time tour guide. Check opportunities for French translation with social workers, Ausflüge and Nachhilfe for English', 'Inactive', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'no', '2025-11-01 20:51:18.791279', '2025-11-01 20:51:18.791279', 326, 449);
