INSERT INTO public.volunteer VALUES (48, '', 'I’m 34 years old and I come from Sweden.I love children and I live in Schöneberg, I’m with Arbeitsamt atm so I have free time and would like to do something good with it.I got my little sister when I was 15 years old, I took care of her a lot when she was small and I’ve also taken care of friends children.I connect very easy with kids and my boyfriend is a Syrian refugee so I also have an understanding of what they might have been through. My German level is B2. -Vostel', 'New', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'no', '2025-11-01 20:51:15.716017', '2025-11-01 20:51:15.716017', 49, 198);
INSERT INTO public.volunteer VALUES (68, '', '- Shawky 13.06.24: If something changes in the future and knowledge of Spanish, Portuguese or French is needed, we will definitely let you know.If your preferences change at some point, you could find a full list of the volunteer opportunities currently available on our website, etc.. / I am from Mexico and moved to Berlin 3 years ago. I am interested in this volunteer opportunity, I am fluent in Spanish, French, Italian, Portuguese and have a B2 level in German. I have always wanted to have the opportunity to help and assist people in need, specially refugees after seeing first hand the experiences some of them had in the north of Mexico near to the border with the United States.  -Vostel', 'Active accompany', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'no', '2025-11-01 20:51:16.181773', '2025-11-01 20:51:16.181773', 69, 173);
