INSERT INTO public.volunteer VALUES (131, '', 'I am Camila from Uruguay. I would be really interested in learning more about this volunteering opportunity. I am looking to be more in contact with children as the little ones bring me a lot of joy and helping them would bring me even more joy :) In case it''s relevant, my German skills are A2-B1, my native language is Spanish and I''m native level speaker in English.At the moment I have availability to come on weekdays at the stated times 18-19:30 Uhr) -Vostel', 'To rematch', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'no', '2025-11-01 20:51:16.960727', '2025-11-01 20:51:16.960727', 132, 190);
INSERT INTO public.volunteer VALUES (137, 'Contact me via whatsapp if needed whenever and I will see my availability', '- Shawky 24.09.2024: Email forwarded to Funda (I am officially B2 German yet I had a C1 6months course. I chose only basic-fluent since in the form there were no intermediate options. Yes I would be comfortable being a Dolmetscher in both De/En/Ar if needed, yet I am more confident speaking Ar/En.)', 'Active accompany', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'no', '2025-11-01 20:51:17.113255', '2025-11-01 20:51:17.113255', 138, 55);
INSERT INTO public.volunteer VALUES (140, 'I''d like to work in gardening, planting trees, etc., and I can also help sort clothes. I''m a teacher with 15 years of experience in Venezuela, but I''ve only been here in Germany for a short time.', 'nadav 11.6: i tried to telegramm call and text, he is not very reactive. i gave up. doesnt seem to have much opportunities for him either..', 'Temp inactive', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'no', '2025-11-01 20:51:17.141341', '2025-11-01 20:51:17.141341', 141, 385);
INSERT INTO public.volunteer VALUES (156, '', '- Shawky 15.10.24: Masters degree in accounting and finance, has banking background. He plays football, volleyball, table tennis, Now looking for a job while taking a German course everyday from 1.00 to 4.30', 'Active accompany', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'no', '2025-11-01 20:51:17.259794', '2025-11-01 20:51:17.259794', 157, 48);
INSERT INTO public.volunteer VALUES (163, '', '- Shawky 23.05.24: Asked her about the daycare opportunity in Chauseestr. / I''m a Turkish woman and I''ve been living in Berlin for 10 months. My native language is Turkish and I speak English fluently. I have a basic level of proficiency in German and I''m trying to improve it. I completed my bachelor in Sociology in Turkey and I''m currently pursuing a master''s degree in urban studies. I''ve been working with children for a while now, providing care services to children from needy families. I am patient with children and genuinely interested in their world.-Vostel', 'Active accompany', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'no', '2025-11-01 20:51:17.311893', '2025-11-01 20:51:17.311893', 164, 195);
INSERT INTO public.volunteer VALUES (178, 'As I am a student and have a mini job as well, my availability might change throughout the next months because of possible classes or be subject to meetings scheduled for my job. I think I still have to figure out how to best integrate volunteer work into my usual schedule. / Contacted for post-match followup.', 'Shawky 31.07.25: She talked to the coordinator at Trachenbergring (https://www.notion.so/Trachenbergring-54403e371fcd447cb9934d556427c503?pvs=21)  about the problem that the children are not attending her hip hop, and then agreed that she would join other projects they are doing just to get to know the kids so that they get to know her. She feels that people at the accommodation center there are not coordinated. She is now volunteering at another accommodation center Refugium Hausvaterweg (https://www.notion.so/Refugium-Hausvaterweg-86c3031b76ee473b8005241a0d82bae4?pvs=21) : She gets a text from them when they need something, mostly helping with children, accompanying them to the cinema, the zoo, etc..), I offered her a T-shirt and sent event invitation for 8. August', 'Active regular', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'yes', '2025-11-01 20:51:17.530543', '2025-11-01 20:51:17.530543', 179, 268);
