INSERT INTO public.volunteer VALUES (203, 'I don’t have my university schedule yet, so I will have to adjust', '- Email from Hubert 05.09.24: Thank you very much for your e mail.I’m doing volunteering to be helpful so if your need is having people to translate in pankow … I can give it a try. This way I will be able to I can see how realist it is with strassbahne (1 hour to come and 1 hour to come back at least) and how I feel there.I can’t promise for now that I will accept this mission, but I’m motivated to give it a try !! Waiting for your answerBest wishes', 'Inactive', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'applied_n4d', '2025-11-01 20:51:17.748963', '2025-11-01 20:51:17.748963', 203, 71);
INSERT INTO public.volunteer VALUES (242, 'Generally flexible for anytime', 'I am a 24 year old Syrian and currently finishing my academic journey at FU Berlin. I can speak English and Arabic with mother tongue proficiency, fluent in German, and can understand and slightly communicate in Spanish. Lately I''ve been finding myself to be a children magnet, so I cannot imagine a better place to help, especially with anything art related as I also think of myself as an artist and have slight experience with guiding art workshops for children.  -Vostel', 'Active accompany', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'no', '2025-11-01 20:51:17.990479', '2025-11-01 20:51:17.990479', 244, 149);
