INSERT INTO public.volunteer VALUES (244, 'Full availability at the moment however this may change upon employment / Experience working with kids, Pediatric occupational therapist in Australia, film and photography. A1.2 language course. Experience in arts/crafts with kids -Vostel.', 'I have just moved to Berlin from Australia and am looking to volunteer with where I can. I have an appointment in mid August to get a working holiday visa for 1 year. I have extensive experience working with children and was a paediatric Occupational Therapist in Australia. I have also worked in the film and photography industry for many years. I have just finished my A1.2 intensive language course however, please note, I am still at a very basic level of understanding and speaking ability thus far. Whilst completing the language course in Mainz, I volunteered to engage in arts and crafts with the refugee kids so have some experience in this work already - I would love to continue this here in Berlin!  -Vostel', 'Inactive', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'no', '2025-11-01 20:51:17.992368', '2025-11-01 20:51:17.992368', 245, 121);
