INSERT INTO public.volunteer VALUES (319, 'Shawky 01.08.2024: She used to be a school teacher for math and physics back in Yemen', 'Hi all!I’m sorry for the late reply. Life has gotten quite busy, and unfortunately, I won’t be able to help this year. However, I hope to be able to assist next year when things settle down, and I’ll contact you when I’m in a better position to help. (Email to Shawky 08.10.24)', 'Active accompany', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'yes', '2025-11-01 20:51:18.737852', '2025-11-01 20:51:18.737852', 320, 96);
INSERT INTO public.volunteer VALUES (340, 'I would mostly prefer the weekend. However, If that is not possible all the time, I can avail myself during the afternoon on some weekdays with prior notice. I live in Frankfurt (Oder).', '- Shawky 22.10.24: He lives in Frankfurt Oder, but can come to Berlin for Nachhilfe (English not German). He is doing his PhD in entrepreneurship management with a focus on refugees, and worked for a law firm in the UK, where he also provided support for asylum seekers. He speaks English, Bengali, Urdu and Hindi.', 'Active accompany', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'no', '2025-11-01 20:51:18.95301', '2025-11-01 20:51:18.95301', 341, 30);
