INSERT INTO public.volunteer VALUES (292, '', '- Nadav Nir Begin forwarded message:From: Volunteer <mailto:volunteer@need4deed.org>Date: 19. September 2024 at 16:00:31 CESTTo: mailto:o.smetanka@icloud.comSubject: Re: Volunteer OpportunitiesHey again, I just thought about another option if you are interested it would perhaps be the most effective one!Members of a women’s group in the refugee accommodation centre in NK (Frauencafe) would like to go out and learn more about Berlin. Volunteers can take them to museums, walk around the neighbourhood or do other fun things. Museums and galleries sometimes provide free tickets for refugees.What do you think?On Thu, Sep 19, 2024 at 3:12 PM Volunteer <mailto:volunteer@need4deed.org> wrote:Thank you for your interest in volunteering through Need4Deed! Most of the opportunities are before 17 so if your schedule is sometimes flexible it would be great to know. Otherwise, there is currently a need in supporting Sommerfest at the 24.09.24 in Lichtenberg 10315. This means either helping out before, during or after! Would this be something you would be interested in? Thanks!', 'Active accompany', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'no', '2025-11-01 20:51:18.476445', '2025-11-01 20:51:18.476445', 293, 50);
