INSERT INTO public.volunteer VALUES (356, 'Hello here,  I am currently looking for an opportunity to volunteer and realize myself in this need.  I am from Ukraine and have been living and working in Berlin for over a year, studying the language.  I am fluent in Ukrainian and Russian. A little worse in English and at an intermediate level in German. But I am constantly working on it.  I work in the IT field, but in the past, while studying at the university, I worked part-time as a tutor in mathematics, Ukrainian language and history mostly with young people.  If you suddenly have a need, I can find free time after 6 pm (Monday, Wednesday, and also up to 3 hours on weekends).  Best wishes, Vadym', '', 'Inactive', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'no', '2025-11-01 20:51:19.060736', '2025-11-01 20:51:19.060736', 357, 415);
INSERT INTO public.volunteer VALUES (360, '', '- Shawky 25.03.2025: He’s an actor (stage and screen), went to art school, studied photography. Does pottery, and had many years experience as a gardener in London. He had experience working with children in a center for kids with autism, helped them learn to read, can also help with Engliish homework. Born in 1976 (does he need a Measles vaccination?), open to commuting up to an hour.', 'Matched', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'no', '2025-11-01 20:51:19.123731', '2025-11-01 20:51:19.123731', 361, 458);
INSERT INTO public.volunteer VALUES (363, '', '- Shawky 21.01.25: She’s from Canada, used to teach dancing classes to children. She is passionate about dancing (hip hop, break dance,), practices meditation and has guided some people before, not professionally though. She is a corporate lawyer, particularly interested in refugee and immigration law, but not an expert. She has a lawyer friend who lives in Frankfurt Oder and could ask if they would be interested in supporting with an event like a panel or post-film discussion. She lives in Wedding and can only volunteer on weekends. Her German level is C1.', 'Matched', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'applied_self', '2025-11-01 20:51:19.231655', '2025-11-01 20:51:19.231655', 364, 490);
