INSERT INTO public.volunteer VALUES (229, 'I am usually available Mon-Fri after 18:00 since I work full-time. I am free on the weekends.', '- Message to Shawky 04.08.2024:  the organizor (Buchholz) reached out and offered me to start immediately. I however had to postpone this since of last minute circumstances with my job.I told them i''d be happy to start at another time in the future and they aggreed. / I am 29 years old, I come from Italy but I am also half German and can speak both languages fluently. I have lots of experience in gardening, especially with permaculture. I have two 72h permaculture design certificates, and I assisted many outdoor projects concerning greenhouses and plants all around the world, volunteering in farms as well. I studied landscape architecture in university before coming in this city. I also have experience in volunteering with refugee organisations. I moved to Berlin 2 years ago, I work a full-time office job, and I miss having my hands in the soil. If I can help in any way let me know, I live in Kreuzberg and can meet up weekly for the project. -Vostel', 'Matched', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'yes', '2025-11-01 20:51:17.890252', '2025-11-01 20:51:17.890252', 230, 152);
