INSERT INTO public.volunteer VALUES (270, '', '31.07.25: She knew about us through Bezirksamt Treptow-Köpenick, She is retired (66 years old) so doesn’t need Masernimpfung. She studies Russian and English at Humboldt university. When Germany was unified, she lost her job as translator, but is certified translator for official documents, she can do direct translation at doctors’ appointments, but needs to be briefed in advance. She worked with Ukrainian families in 2022, and worked a bit in the US, so her English is very good, She worked for an American law firm in Berlin, and then changed her career to become an IT trainer. We agreed she will start with summer festivals and see (because she is in Rente, she travels a lot and can’t commit to a fixed weekly schedule)', 'To rematch', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'yes', '2025-11-01 20:51:18.215728', '2025-11-01 20:51:18.215728', 271, 320);
