INSERT INTO public.volunteer VALUES (295, 'Hello dear community, I have a 5 volunteering day paid leave from my work that I want to use for a good cause this year with volunteering. I saw this opportunity that I thought I might be a good fit but I am also open for other opportunities. What is important for me is that I can commit to it for only 10 weeks in half days and preferably on Friday afternoon as I need to submit these days to my manager as soon as possible for approval. I would also appreciate if I could get somehow a participation letter that could be a proof. Please let me know if you can provide me these and if I need to do anything else to become a volunteer starting from February 7th until April 11th on Fridays in the afternoons.', 'Nadav 22.1.25: He is in Turkey right now he cannot volunteer on mondays. once he is back next week we will have an intro talk (for translation support and general i guess together)', 'Inactive', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'yes', '2025-11-01 20:51:18.486064', '2025-11-01 20:51:18.486064', 296, 476);
