INSERT INTO public.volunteer VALUES (395, 'I''m really good at playing the clarinet and sing so I can help and volunteer in teaching music', 'Senya 11.07.25: From the VC: Ein Mädchen aus Dänemark hatte angefragt aber leider hat es mit dem Führungszeugnis beantragen nicht funktioniert… sie ist nur ein Semester hier und hätte das ohne Wohnsitz in Bonn beantragen müssen und cih glaube, am Ende war alles zu kompliziert leider!”', 'Matched', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'applied_self', '2025-11-01 20:51:19.546405', '2025-11-01 20:51:19.546405', 396, 461);
INSERT INTO public.volunteer VALUES (411, '', 'Vostel 28.07.25: “Sehr geehrte Damen und Herren,ich suche derzeit nach einer Möglichkeit, mich wieder in der Flüchtlingshilfe zu engagieren. 2015 bis 2019 habe ich schon in dem Bereich mich ehrenamtlich engagiert bzw. für verschiedene Organisationen gearbeitet. Ich bin bilingual aufgewachsen (Arabisch-Deutsch) und habe 6 Jahre meiner Kindheit und Jugend in Syrien gelebt. Daher spreche ich fließend Arabisch und kenne mich gut mit den kulturellen Gepflogenheiten für den Raum aus. Damals habe ich Menschen zu ihren Terminen als Sprachmittler begleitet und ihnen bei Briefen und Formularen geholfen. Also so ziemlich das, wonach Sie in Ihrem Inserat suchen. Das Engagement von damals würde ich sehr gerne wieder aufnehmen. Meine Stärken liegen im richtigen Umgang mit Menschen, einer emphatischen Art und natürlich meiner Zweisprachigkeit.Wenn da bei Ihnen Bedarf besteht, bin ich gerne da um auszuhelfen.”
INSERT INTO public.volunteer VALUES (412, 'Preferred time frame would be either fridays (any time) or on the weekend.', 'Shawky 06.05.25: She got busy and cannot volunteer anymore, will let us know if something changes.
