INSERT INTO public.volunteer VALUES (531, 'Valid from 21st July 2025 until 30th July. Before starting my new job I have 2 weeks off. I have worked in big companies as Executive Assistant and also in a ministry recently, so I know German bureaucracy and also real estate agents etc. Very well and would like to help. Lots of experience in Hospitality & Event Management, Star Trek, Architecture / Guide Tours, Club Culture, Chaos Computer Club', 'Shawky 25.07.25: Sent her asking if she is only available to volunteer for the two weeks in July she mentioned in her comments. She replied that she doesn’t know yet and I told her to get in touch when she knows, invited her to the Telegram group.', 'Temp inactive', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'yes', '2025-11-01 20:51:20.463162', '2025-11-01 20:51:20.463162', 534, 342);
