INSERT INTO public.volunteer VALUES (459, 'Hello, My name is Kerstin Larsson and I am a student pursuing my master''s degree in Paris in International Development. I will be going to Berlin over the summer from June 22 for at least a month, probably longer. I will be studying German each day from 9-12.30 during the weeks and the hours after that I would like to help out and volunteer. I am also available during the weekends. Please let me know if you need any additional information about me and my experiences. Best regards/ Kerstin Larsson', '', 'Inactive', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'no', '2025-11-01 20:51:20.104338', '2025-11-01 20:51:20.104338', 461, 392);
INSERT INTO public.volunteer VALUES (472, '', 'Shawky 30.07.25: She works in IT, can only volunteer in weekends or in the evenings during the week. She volunteered in Morocco with children with cancer, playing and doing activities with them, Her German is strong enough to do German Unterricht with women (specially Arabic-speaking women) as well as with children who need help. I am inquiring with Senya about the possibility of this opportunity in Töpchiner Weg to see if it is possible for the weekends: @Organisiere Aktivitäten für Frauen', 'Matched', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'no', '2025-11-01 20:51:20.14847', '2025-11-01 20:51:20.14847', 474, 327);
