INSERT INTO public.volunteer VALUES (509, 'I''m a fully qualified fitness coach', 'Nadav 22.4: she lives in mittte, wants to do sports, right now is not working day time but this can change. does not want to volunteer deep in the east because of posssisble racism (she is black). We will try to match her with charlottenburg hotel Hotel Plaza Inn (https://www.notion.so/Hotel-Plaza-Inn-1ac8d880f4748089ab25c7c31784b3e9?pvs=21)', 'Active regular', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'applied_self', '2025-11-01 20:51:20.312724', '2025-11-01 20:51:20.312724', 511, 419);
