INSERT INTO public.volunteer VALUES (452, 'Liebes Need4Deed-Team,  ich bin Vater von zwei kleinen Kindern (4 und 7 Jahre alt), lebe in Schöneberg, Berlin und arbeite an einer Universität. Ich komme ursprünglich aus Russland, spreche Russisch als Muttersprache und habe etwa B2-Niveau in Deutsch.  Da ich selbst viel Freude daran habe, Zeit mit Kindern zu verbringen, würde ich mich sehr freuen, geflüchtete Kinder in der Gemeinschaftsunterkunft zu unterstützen – sei es beim Spielen, Basteln oder einfach im gemeinsamen Alltag. Es wäre schön, einen kleinen Beitrag zu ihrem Wohlbefinden leisten zu können.  Ich freue mich auf Ihre Rückmeldung!  Herzliche Grüße, Philipp Chapkovski, Ph.D https://chapkovski.github.io/ +4915123570022', '- Teaches at the university (political science and sociology), he has 2 children (Elternsinitiative in school), so has experience jumping in for teachers when needed.', 'Matched', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'applied_n4d', '2025-11-01 20:51:20.01053', '2025-11-01 20:51:20.01053', 454, 438);
