INSERT INTO public.volunteer VALUES (489, '', 'Nadav 28.4.25: did a lot of creatives things with adults bit with kids too with finnished . nachhilfe can also work. asked about  @Senya can you ask seehoferstr if they need nach hilfe or kinderbetreuung she might be soon avilable in afternoon but so far its this schedule but she has good teaching exoperince and weekend also option if they can. otherwise storkowerstr', 'Active regular', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'yes', '2025-11-01 20:51:20.229594', '2025-11-01 20:51:20.229594', 492, 412);
INSERT INTO public.volunteer VALUES (498, '', 'Shawky 15.07.25: born in Austria, speaks Tunisian Arabic too. She works professionally as an actress and dancer, and would love to volunteer —especially playing and working with children, creating joyful and meaningful moments together.', 'Opportunity sent', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'applied_n4d', '2025-11-01 20:51:20.27161', '2025-11-01 20:51:20.27161', 500, 361);
INSERT INTO public.volunteer VALUES (499, '', 'Shawky 04.08.25: From Vostel: “mein Name ist Chiara und ich bin zertifizierte Yogalehrerin (Yoga Alliance), ausgebildet in Indien mit Schwerpunkt auf Hatha-Yoga, Atemarbeit sowie Klangheilung (Sound Healing/Sound Bath). Ich lebe in Berlin ( Ostkreuz) und möchte gerne meine Zeit, Energie und Fähigkeiten ehrenamtlich zur Verfügung stellen, um Ihre wichtige Arbeit zu unterstützen. Ich bin überzeugt, dass Yoga, insbesondere in Gemeinschaft, sowohl körperliche als auch seelische Stärke fördern kann – und Momente der Ruhe und Verbundenheit schafft, gerade für Menschen in schwierigen Lebenssituationen.In der Vergangenheit habe ich bereits in Italien und Berlin als freiwillige Yogalehrerin in verschiedenen sozialen Einrichtungen gearbeitet. Zurzeit unterrichte ich Yoga weiterhin ehrenamtlich in meinem Kiez und an der Universität.Beruflich komme ich ursprünglich aus dem Mode- und E-Commerce-Bereich als Merchandise Planner und Data Analyst. Aktuell konzentriere ich mich jedoch ganz auf meine Weiterbildung in den Bereichen Ayurveda, Yoga und Deutsch. Ich habe kürzlich ein C1-Zertifikat in Deutsch erworben und spreche Italienisch, Spanisch, Russisch, Englisch und Deutsch.Ich freue mich sehr, meine Zeit und mein Wissen im Rahmen Ihrer Projekte einzubringen. Ich bin unter der Woche zeitlich flexibel und freue mich auf Ihre Rückmeldung.Vielen dank,Chiara”', 'New', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'no', '2025-11-01 20:51:20.275857', '2025-11-01 20:51:20.275857', 501, 312);
INSERT INTO public.volunteer VALUES (506, '', '9 July JCi, I spoke with her, and she’s more interested in helping with smaller tasks, such as assisting with the summer fest, yoga for women, or activities for seniors and children. She doesn’t feel comfortable with her level of German yet, she is more flexible in September and she is interested on practicing her German.', 'Temp inactive', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'no', '2025-11-01 20:51:20.292777', '2025-11-01 20:51:20.292777', 508, 373);
