INSERT INTO public.volunteer VALUES (517, '', 'Shawky 04.08.25: E-Mail “Hallo zusammen,  ich würde mich gerne beim Sommerfest in Tegel am 22.08. engagieren, hier hat sich auch eine Kommilitonin von mir angemeldet. Das Ausschreiben finde ich auf der Webseite jedoch nicht. Sind denn noch Freiwillige gesucht? Ich würde mich darüber freuen, mich melden zu dürfen.” E-mailed back to let them know the festival is in Lichtenberg, copied Senya', 'To rematch', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'yes', '2025-11-01 20:51:20.364705', '2025-11-01 20:51:20.364705', 519, 326);
INSERT INTO public.volunteer VALUES (521, '', 'Shawky 21.07.25: Sozialwissenschaft studiert, möchte mehr Leute kennenlernen, Wohnt in Berlin seit einem Jahr und kann mit Frauen (nicht Männern) oder Kindern arbeiten. Arbeitet in Senatverwaltung für Jugend und Familie in Reinickendorf, wohnt in Wedding, aber zieht bald nach Prenzlauer Berg. Kann nur nach 17.00 Uhr im Laufe der Woche oder an Wochenende. Ich habe die Link für Angebote geschickt.', 'Opportunity sent', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'applied_n4d', '2025-11-01 20:51:20.403954', '2025-11-01 20:51:20.403954', 524, 338);
INSERT INTO public.volunteer VALUES (527, 'Hello,', 'Shawky 01.07.25: Syrian, Interested in Kleiderkammer, also in festivals. Likes cooking a lot. Studies energy engineering in Syria. He was giving computer courses in refugees, works in the humanitarian field, more on the technical side. He lived in Prague before, plays guitar, and has played before in refugee contexts. He seems more interested in one-day events, he came to our events several times and like', 'Active regular', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'yes', '2025-11-01 20:51:20.443499', '2025-11-01 20:51:20.443499', 530, 483);
INSERT INTO public.volunteer VALUES (530, '', 'Shawky 13.05.25: Native Berliner. He is studying computer science (business informatics), currently doing an internship. He likes sports with kids with migration backgrounds (he played in the basketball league and plays volleyball too, but also football). He prefers working with children, he was working for a Kindergarten before assisting teachers. He can help with Nachhilfe (Math, Chemistry & German). He lives in Schöneberg/Friedenau (closer to Steglitz). His office is close to the Hauptbahnhof, so can travel from there  as well up to 30-40 mins commute.', 'Inactive', NULL, NULL, NULL, NULL, NULL, NULL, 'no', 'applied_n4d', '2025-11-01 20:51:20.457796', '2025-11-01 20:51:20.457796', 533, 394);
INSERT INTO public.volunteer VALUES (492, '', '- Shawky 28.01.2025: He studied all his life in the German school in Cairo, so can speak German fluently and is familiar with the education system. Works as a software developer, been in Germany for 10 years. Can help with Nachhilfe, particularly for Math and science, as well as German. He can also help teenagers with university applications. He can only volunteer after 5 during the week or on weekends. 
INSERT INTO public.volunteer VALUES (493, 'I have long experience working with children, both due to professional activities (summer schools, baby sitting) and as a volunteer, more recently worked with an association offering after school activities of an underserved community in the amazons in Peru.', 'She’s Italian, been living in Berlin for 6 years. She is taking a break. She has a long experience working in HR, so can also help with job placement for teenagers and adults. She can volunteer in NK or Tempelhof, but willing to travel elsewhere. She has a valid EFZ.', 'Matched', NULL, NULL, NULL, NULL, NULL, NULL, 'yes', 'yes', '2025-11-01 20:51:20.242149', '2025-11-01 20:51:20.242149', 495, 397);
